{
  "name": "AdjusterAI: Smart Repair Estimator",
  "description": "An AI-powered insurance estimating assistant that analyzes damage photos and synopses against carrier guidelines to generate Xactimate and Symbility-ready line items and labeled photo reports.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Platform {
  XACTIMATE = 'Xactimate',
  SYMBILITY = 'Symbility'
}

export interface Room {
  id: string;
  name: string;
  type: 'Room' | 'Exterior Face';
}

export interface Photo {
  id: string;
  roomId: string;
  base64: string;
  mimeType: string;
  fileName: string;
  label?: string;
  suggestedLineItems?: string[];
}

export interface LineItem {
  id: string;
  code: string;
  description: string;
  quantity: number;
  unit: string;
  roomName: string;
}

export interface EstimationState {
  carrier: string;
  synopsis: string;
  platform: Platform;
  guidelinesUrl?: string;
  customGuidelines?: string;
  rooms: Room[];
  photos: Photo[];
  lineItems: LineItem[];
  isAnalyzing: boolean;
  analysisComplete: boolean;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Platform, Photo, LineItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchCarrierGuidelines = async (carrier: string): Promise<string> => {
  const prompt = `Find the 2024-2025 property estimating and repair guidelines for the insurance carrier: ${carrier}. 
  Summarize key rules for material waste, overhead and profit, and common estimating line item requirements.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    return response.text || "No specific guidelines found via search.";
  } catch (error) {
    console.error("Error fetching guidelines:", error);
    return "Error retrieving carrier guidelines.";
  }
};

export const analyzeDamage = async (
  platform: Platform,
  carrier: string,
  synopsis: string,
  guidelines: string,
  photos: Photo[],
  rooms: { [id: string]: string }
): Promise<{ lineItems: LineItem[]; labeledPhotos: Photo[] }> => {

  // Prepare multimodal prompt
  const imageParts = photos.map(p => ({
    inlineData: {
      data: p.base64.split(',')[1] || p.base64,
      mimeType: p.mimeType
    }
  }));

  const prompt = `
    You are an expert insurance adjuster specializing in ${platform}.
    Insurance Carrier: ${carrier}
    Carrier Guidelines: ${guidelines}
    User Damage Synopsis: ${synopsis}

    Instructions:
    1. Analyze the provided photos of property damage.
    2. Based on the ${platform} platform, determine the correct line items (codes and descriptions) needed for repair.
    3. For each photo, provide a descriptive label suitable for an insurance report (e.g., "Living Room - North Wall: Significant moisture staining on drywall").
    4. Group the line items by the room they belong to.

    Output in strict JSON format:
    {
      "lineItems": [
        { "code": "DRY 1/2", "description": "1/2 inch drywall - hang, tape, sand - ready for paint", "quantity": 1, "unit": "SF", "roomName": "Name of Room" }
      ],
      "photoLabels": [
        { "photoId": "id_from_input", "label": "The generated label" }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { 
        parts: [
          ...imageParts, 
          { text: prompt + `\n\nNote: The photo IDs are as follows in order: ${photos.map(p => p.id).join(', ')}` }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            lineItems: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  code: { type: Type.STRING },
                  description: { type: Type.STRING },
                  quantity: { type: Type.NUMBER },
                  unit: { type: Type.STRING },
                  roomName: { type: Type.STRING }
                },
                required: ["code", "description", "quantity", "unit", "roomName"]
              }
            },
            photoLabels: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  photoId: { type: Type.STRING },
                  label: { type: Type.STRING }
                },
                required: ["photoId", "label"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || '{}');

    // Map labels back to original photo objects
    const labeledPhotos = photos.map(p => {
      const match = result.photoLabels?.find((l: any) => l.photoId === p.id);
      return { ...p, label: match?.label || "Damage view" };
    });

    return {
      lineItems: result.lineItems.map((li: any, index: number) => ({ ...li, id: `li-${index}` })),
      labeledPhotos
    };
  } catch (error) {
    console.error("AI Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
  Download,
  AlertCircle
} from 'lucide-react';
import { Platform, Room, Photo, EstimationState, LineItem } from './types';
import { fetchCarrierGuidelines, analyzeDamage } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [state, setState] = useState<EstimationState>({
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    photos: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    customGuidelines: ''
  });

  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const addRoom = (name: string, type: 'Room' | 'Exterior Face') => {
    const newRoom: Room = { id: crypto.randomUUID(), name, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const removeRoom = (id: string) => {
    setState(prev => ({ 
      ...prev, 
      rooms: prev.rooms.filter(r => r.id !== id),
      photos: prev.photos.filter(p => p.roomId !== id)
    }));
  };

  const handleFileUpload = (roomId: string, files: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const base64 = e.target?.result as string;
        const newPhoto: Photo = {
          id: crypto.randomUUID(),
          roomId,
          base64,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, photos: [...prev.photos, newPhoto] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const handleFetchGuidelines = async () => {
    if (!state.carrier) return;
    setGuidelinesLoading(true);
    const g = await fetchCarrierGuidelines(state.carrier);
    setFetchedGuidelines(g);
    setGuidelinesLoading(false);
  };

  const runAnalysis = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform,
        state.carrier,
        state.synopsis,
        state.customGuidelines || fetchedGuidelines,
        state.photos,
        roomMap
      );
      setState(prev => ({
        ...prev,
        lineItems: result.lineItems,
        photos: result.labeledPhotos,
        isAnalyzing: false,
        analysisComplete: true
      }));
      nextStep();
    } catch (err) {
      alert("Analysis failed. Please try again.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Header */}
      <header className="flex items-center justify-between mb-8 pb-4 border-b border-slate-200">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white">
            <ClipboardCheck size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">AdjusterAI</h1>
            <p className="text-sm text-slate-500 font-medium">Smart Repair Estimator</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1">
            {[1, 2, 3, 4, 5].map(i => (
              <div 
                key={i} 
                className={`h-2 w-8 rounded-full transition-colors ${i <= step ? 'bg-indigo-600' : 'bg-slate-200'}`}
              />
            ))}
          </div>
          <span className="text-xs font-bold text-slate-400 uppercase">Step {step} of 5</span>
        </div>
      </header>

      {/* Step 1: Initial Setup */}
      {step === 1 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
          <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
            <Building2 className="text-indigo-600" />
            Project Fundamentals
          </h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <label className="block text-sm font-semibold text-slate-700">Insurance Carrier</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  placeholder="e.g. State Farm, Allstate"
                  className="flex-1 px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={state.carrier}
                  onChange={e => setState(p => ({ ...p, carrier: e.target.value }))}
                />
                <button 
                  onClick={handleFetchGuidelines}
                  disabled={!state.carrier || guidelinesLoading}
                  className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                >
                  {guidelinesLoading ? <Loader2 className="animate-spin" size={16} /> : <FileText size={16} />}
                  Find Guidelines
                </button>
              </div>

              {fetchedGuidelines && (
                <div className="mt-4 p-4 bg-indigo-50 border border-indigo-100 rounded-lg">
                  <h3 className="text-xs font-bold text-indigo-700 uppercase mb-2">Carrier Guidelines Summary</h3>
                  <p className="text-sm text-indigo-900 italic">"{fetchedGuidelines.substring(0, 200)}..."</p>
                </div>
              )}

              <div className="pt-4">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    onClick={() => setState(p => ({ ...p, platform: Platform.XACTIMATE }))}
                    className={`py-3 px-4 rounded-xl border-2 text-center font-bold transition-all ${state.platform === Platform.XACTIMATE ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-200 bg-white text-slate-400'}`}
                  >
                    Xactimate
                  </button>
                  <button 
                    onClick={() => setState(p => ({ ...p, platform: Platform.SYMBILITY }))}
                    className={`py-3 px-4 rounded-xl border-2 text-center font-bold transition-all ${state.platform === Platform.SYMBILITY ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-200 bg-white text-slate-400'}`}
                  >
                    Symbility
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <label className="block text-sm font-semibold text-slate-700">Damage Synopsis</label>
              <textarea 
                rows={8}
                placeholder="Describe the scope of damage (e.g., 'Category 3 water intrusion from roof leak affecting ceiling and north wall of living room...')"
                className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                value={state.synopsis}
                onChange={e => setState(p => ({ ...p, synopsis: e.target.value }))}
              />
            </div>
          </div>

          <div className="mt-8 flex justify-end">
            <button 
              onClick={nextStep}
              disabled={!state.carrier || !state.synopsis}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-3 rounded-lg font-bold flex items-center gap-2 transition-all shadow-md active:scale-95"
            >
              Next: Define Structure
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Structure/Diagram */}
      {step === 2 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold flex items-center gap-2">
              <Building2 className="text-indigo-600" />
              Define Rooms & Structure Faces
            </h2>
            <div className="flex gap-2">
              <button 
                onClick={() => addRoom(`Room ${state.rooms.length + 1}`, 'Room')}
                className="px-4 py-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 rounded-lg text-sm font-bold flex items-center gap-2"
              >
                <Plus size={16} /> Add Room
              </button>
              <button 
                onClick={() => addRoom(`Elevation ${state.rooms.length + 1}`, 'Exterior Face')}
                className="px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-bold flex items-center gap-2"
              >
                <Plus size={16} /> Add Exterior Face
              </button>
            </div>
          </div>

          {state.rooms.length === 0 ? (
            <div className="text-center py-20 border-2 border-dashed border-slate-200 rounded-2xl">
              <p className="text-slate-400 font-medium">No rooms defined. Add your first room or elevation to start uploading photos.</p>
            </div>
          ) : (
            <div className="grid md:grid-cols-3 gap-4">
              {state.rooms.map(room => (
                <div key={room.id} className="p-4 border border-slate-200 rounded-xl hover:border-indigo-300 transition-all flex items-center justify-between group">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded ${room.type === 'Room' ? 'bg-indigo-100 text-indigo-600' : 'bg-amber-100 text-amber-600'}`}>
                      {room.type === 'Room' ? <Building2 size={18} /> : <Camera size={18} />}
                    </div>
                    <div>
                      <input 
                        className="font-bold text-slate-700 focus:outline-none focus:ring-1 focus:ring-indigo-500 px-1 rounded"
                        value={room.name}
                        onChange={(e) => {
                          const newName = e.target.value;
                          setState(p => ({
                            ...p,
                            rooms: p.rooms.map(r => r.id === room.id ? { ...r, name: newName } : r)
                          }));
                        }}
                      />
                      <p className="text-xs text-slate-400">{room.type}</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => removeRoom(room.id)}
                    className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              ))}
            </div>
          )}

          <div className="mt-8 flex justify-between">
            <button onClick={prevStep} className="px-6 py-2 text-slate-500 font-bold hover:text-slate-700">Back</button>
            <button 
              onClick={nextStep}
              disabled={state.rooms.length === 0}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-3 rounded-lg font-bold flex items-center gap-2 transition-all shadow-md active:scale-95"
            >
              Next: Upload Photos
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* Step 3: Photo Upload per Room */}
      {step === 3 && (
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
            <h2 className="text-xl font-bold mb-2 flex items-center gap-2">
              <Camera className="text-indigo-600" />
              Upload & Organize Damage Photos
            </h2>
            <p className="text-sm text-slate-500 mb-8">Click 'Upload' in the corresponding room section to add photos of the damage.</p>

            <div className="space-y-8">
              {state.rooms.map(room => (
                <div key={room.id} className="border-t border-slate-100 pt-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg text-slate-800">{room.name}</h3>
                    <label className="cursor-pointer bg-slate-100 hover:bg-slate-200 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-colors">
                      <Plus size={16} /> Upload Photos
                      <input 
                        type="file" 
                        multiple 
                        accept="image/*"
                        className="hidden"
                        onChange={(e) => handleFileUpload(room.id, e.target.files)}
                      />
                    </label>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                    {state.photos.filter(p => p.roomId === room.id).map(photo => (
                      <div key={photo.id} className="relative aspect-square rounded-xl overflow-hidden border border-slate-200 group">
                        <img src={photo.base64} alt="damage" className="w-full h-full object-cover" />
                        <button 
                          onClick={() => setState(p => ({ ...p, photos: p.photos.filter(ph => ph.id !== photo.id) }))}
                          className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    ))}
                    {state.photos.filter(p => p.roomId === room.id).length === 0 && (
                      <div className="col-span-full py-8 text-center bg-slate-50 border border-dashed border-slate-200 rounded-xl">
                        <p className="text-xs text-slate-400 font-medium italic">No photos uploaded for this room</p>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-between border-t border-slate-100 pt-8">
              <button onClick={prevStep} className="px-6 py-2 text-slate-500 font-bold hover:text-slate-700">Back</button>
              <button 
                onClick={runAnalysis}
                disabled={state.photos.length === 0 || state.isAnalyzing}
                className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-10 py-4 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg active:scale-95 text-lg"
              >
                {state.isAnalyzing ? (
                  <>
                    <Loader2 className="animate-spin" />
                    Analyzing Scope...
                  </>
                ) : (
                  <>
                    <CheckCircle2 size={24} />
                    Run AI Damage Analysis
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Step 4 & 5: Results & Export */}
      {step >= 4 && (
        <div className="space-y-8 animate-in fade-in duration-700">
          {/* Summary Stats */}
          <div className="grid md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Total Line Items</p>
              <h3 className="text-3xl font-bold text-indigo-600">{state.lineItems.length}</h3>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Carrier Guidelines</p>
              <h3 className="text-3xl font-bold text-slate-700">Applied</h3>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Export Format</p>
              <h3 className="text-3xl font-bold text-amber-600">{state.platform}</h3>
            </div>
          </div>

          <div className="grid lg:grid-cols-2 gap-8">
            {/* Line Items List */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                <h2 className="text-xl font-bold flex items-center gap-2">
                  <FileText className="text-indigo-600" />
                  Proposed Line Items
                </h2>
                <button className="text-indigo-600 font-bold text-sm hover:underline flex items-center gap-1">
                  <Download size={14} /> Export ESX/CSV
                </button>
              </div>
              <div className="flex-1 overflow-auto max-h-[600px] p-6 space-y-6">
                {state.rooms.map(room => {
                  const roomItems = state.lineItems.filter(li => li.roomName === room.name);
                  if (roomItems.length === 0) return null;
                  return (
                    <div key={room.id}>
                      <h3 className="font-bold text-slate-800 mb-3 text-sm uppercase tracking-wider bg-slate-100 px-3 py-1 rounded inline-block">{room.name}</h3>
                      <div className="space-y-2">
                        {roomItems.map(item => (
                          <div key={item.id} className="p-3 border border-slate-100 rounded-lg bg-white shadow-sm flex items-start justify-between">
                            <div>
                              <p className="font-bold text-slate-900 text-sm">{item.code}</p>
                              <p className="text-xs text-slate-500 leading-tight mt-0.5">{item.description}</p>
                            </div>
                            <div className="text-right">
                              <p className="text-sm font-bold text-indigo-600">{item.quantity} {item.unit}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Labeled Photos */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                <h2 className="text-xl font-bold flex items-center gap-2">
                  <Camera className="text-indigo-600" />
                  Labeled Photo Report
                </h2>
                <button className="text-indigo-600 font-bold text-sm hover:underline flex items-center gap-1">
                  <Download size={14} /> Download PDF
                </button>
              </div>
              <div className="flex-1 overflow-auto max-h-[600px] p-6 grid grid-cols-1 gap-6">
                {state.photos.map(photo => {
                  const room = state.rooms.find(r => r.id === photo.roomId);
                  return (
                    <div key={photo.id} className="group">
                      <div className="relative aspect-video rounded-xl overflow-hidden border border-slate-200">
                        <img src={photo.base64} alt="Labeled damage" className="w-full h-full object-cover" />
                        <div className="absolute top-2 left-2 px-3 py-1 bg-black/50 backdrop-blur-md rounded text-white text-xs font-bold uppercase">
                          {room?.name}
                        </div>
                      </div>
                      <div className="mt-3 p-3 bg-slate-50 rounded-lg border border-slate-100">
                        <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Xactimate/Symbility Label</label>
                        <p className="text-sm text-slate-700 font-medium leading-relaxed italic">
                          {photo.label || "Generating description..."}
                        </p>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button 
              onClick={() => window.location.reload()}
              className="px-12 py-4 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center gap-3 shadow-xl hover:-translate-y-1"
            >
              <Plus size={24} /> Start New Inspection
            </button>
          </div>
        </div>
      )}

      {/* Footer Info */}
      <footer className="mt-12 pt-8 border-t border-slate-200 text-center space-y-2 pb-12">
        <div className="flex items-center justify-center gap-6 text-xs font-bold text-slate-400 uppercase tracking-widest">
