import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Platform, Photo, LineItem, DamageCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchCarrierGuidelines = async (carrier: string): Promise<string> => {
  const prompt = `Find the 2024-2025 property estimating and repair guidelines for the insurance carrier: ${carrier}. 
  Focus on technical requirements for water mitigation, fire remediation, and structural repairs. 
  Summarize key rules for material waste, overhead and profit, and mandatory line items.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    return response.text || "No specific guidelines found via search.";
  } catch (error) {
    console.error("Error fetching guidelines:", error);
    return "Error retrieving carrier guidelines.";
  }
};

export const analyzeDamage = async (
  platform: Platform,
  carrier: string,
  synopsis: string,
  guidelines: string,
  photos: Photo[],
  rooms: { [id: string]: string }
): Promise<{ lineItems: LineItem[]; labeledPhotos: Photo[] }> => {

  const imageParts = photos.map(p => ({
    inlineData: {
      data: p.base64.split(',')[1] || p.base64,
      mimeType: p.mimeType
    }
  }));

  const prompt = `
    You are an expert Forensic Insurance Adjuster and Estimator.
    Platform: ${platform}
    Carrier: ${carrier}
    Guidelines: ${guidelines}
    Claim Synopsis: ${synopsis}

    TASK:
    1. Damage Detection: For each photo, identify the specific damage category (Water, Fire, Structural, Cosmetic, or Mold/Microbial).
    2. Forensic Analysis: Provide technical observations (e.g., "Circular staining with 3-inch bleed indicative of active leak," or "Spider-web cracking suggesting load-bearing fatigue").
    3. Line Item Generation: Produce highly accurate ${platform} line items based on visual evidence. Include a 'justification' field explaining why the item is required based on carrier guidelines and the specific photo evidence.
    4. Report Labeling: Create a professional photo label (e.g., "Living Room: Northeast corner view showing saturated baseboards and drywall wicking").

    OUTPUT SCHEMA REQUIREMENTS:
    Return valid JSON matching the provided schema. Ensure every photo from the input has a corresponding entry in photoResults.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { 
        parts: [
          ...imageParts, 
          { text: prompt + `\n\nInput Photo Order (IDs): ${photos.map(p => p.id).join(', ')}` }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            lineItems: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  code: { type: Type.STRING },
                  description: { type: Type.STRING },
                  quantity: { type: Type.NUMBER },
                  unit: { type: Type.STRING },
                  roomName: { type: Type.STRING },
                  justification: { type: Type.STRING }
                },
                required: ["code", "description", "quantity", "unit", "roomName", "justification"]
              }
            },
            photoResults: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  photoId: { type: Type.STRING },
                  label: { type: Type.STRING },
                  damageCategory: { type: Type.STRING, description: "Must be one of: Water, Fire, Structural, Cosmetic, Mold/Microbial" },
                  confidence: { type: Type.NUMBER, description: "0.0 to 1.0" },
                  observations: { type: Type.STRING }
                },
                required: ["photoId", "label", "damageCategory", "confidence", "observations"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || '{}');

    const labeledPhotos = photos.map(p => {
      const match = result.photoResults?.find((l: any) => l.photoId === p.id);
      return { 
        ...p, 
        label: match?.label || "Site condition photo",
        detectedDamage: match ? {
          category: match.damageCategory as DamageCategory,
          confidence: match.confidence,
          observations: match.observations
        } : undefined
      };
    });

    return {
      lineItems: result.lineItems.map((li: any, index: number) => ({ ...li, id: `li-${index}` })),
      labeledPhotos
    };
  } catch (error) {
    console.error("Advanced AI Analysis Error:", error);
    throw error;
  }
};

