                        <div className="pt-3 border-t border-slate-100">
                          <label className="text-[10px] font-bold text-indigo-400 uppercase mb-1 block">Xactimate/Symbility Label</label>
                          <p className="text-sm text-indigo-900 italic font-semibold">
                            {photo.label}
                          </p>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Line Items List (Right Column) */}
            <div className="lg:col-span-3">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 flex flex-col h-full">
                <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                  <h2 className="text-xl font-bold flex items-center gap-2">
                    <FileText className="text-indigo-600" />
                    Recommended Scope
                  </h2>
                  <div className="flex gap-3">
                    <button className="text-slate-600 bg-white border border-slate-200 px-4 py-2 rounded-lg font-bold text-sm hover:bg-slate-50 flex items-center gap-2 transition-all">
                      <Download size={14} /> CSV
                    </button>
                    <button className="text-white bg-indigo-600 px-4 py-2 rounded-lg font-bold text-sm hover:bg-indigo-700 flex items-center gap-2 shadow-sm transition-all">
                      <Download size={14} /> {state.platform} .ESX
                    </button>
                  </div>
                </div>

                <div className="flex-1 p-6 space-y-8">
                  {state.rooms.map(room => {
                    const roomItems = state.lineItems.filter(li => li.roomName === room.name);
                    if (roomItems.length === 0) return null;
                    return (
                      <div key={room.id} className="animate-in fade-in slide-in-from-left-2 duration-500">
                        <div className="flex items-center gap-2 mb-4">
                           <div className="h-4 w-1 bg-indigo-500 rounded-full"></div>
                           <h3 className="font-bold text-slate-800 text-sm uppercase tracking-wider">{room.name}</h3>
                        </div>
                        <div className="grid gap-3">
                          {roomItems.map(item => (
                            <div key={item.id} className="p-4 border border-slate-100 rounded-xl bg-slate-50/50 hover:bg-white hover:shadow-md transition-all group">
                              <div className="flex items-start justify-between gap-4 mb-2">
                                <div>
                                  <div className="flex items-center gap-2">
                                    <span className="font-mono text-xs font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100">{item.code}</span>
                                    <span className="font-bold text-slate-900">{item.description}</span>
                                  </div>
                                </div>
                                <div className="text-right shrink-0">
                                  <p className="text-sm font-black text-slate-900">{item.quantity} {item.unit}</p>
                                </div>
                              </div>
                              <div className="flex items-start gap-2 text-slate-500 bg-white p-2 rounded-lg border border-slate-100 text-[11px] leading-relaxed">
                                <Info size={14} className="mt-0.5 shrink-0 text-slate-300" />
                                <span><strong className="text-slate-600 uppercase text-[9px]">AI Justification:</strong> {item.justification}</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button 
              onClick={() => window.location.reload()}
              className="px-12 py-4 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center gap-3 shadow-xl hover:-translate-y-1"
            >
              <Plus size={24} /> Start New Inspection
            </button>
          </div>
        </div>
      )}

      {/* Footer Info */}
      <footer className="mt-12 pt-8 border-t border-slate-200 text-center space-y-2 pb-12">
        <div className="flex items-center justify-center gap-6 text-xs font-bold text-slate-400 uppercase tracking-widest">
          <span>Forensic Analysis</span>
          <span className="h-1 w-1 bg-slate-300 rounded-full"></span>
          <span>Carrier-Compliant</span>
          <span className="h-1 w-1 bg-slate-300 rounded-full"></span>
          <span>Encrypted</span>
        </div>
        <p className="text-xs text-slate-400">© 2024 AdjusterAI Estimating Solutions. Gemini 3.0 Advanced Pro Analysis Engine.</p>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #cbd5e1;
        }
      `}</style>
    </div>
  );
};

export default App;

export enum Platform {
  XACTIMATE = 'Xactimate',
  SYMBILITY = 'Symbility'
}

export type DamageCategory = 'Water' | 'Fire' | 'Structural' | 'Cosmetic' | 'Mold/Microbial' | 'Unknown';

export interface Room {
  id: string;
  name: string;
  type: 'Room' | 'Exterior Face';
}

export interface Photo {
  id: string;
  roomId: string;
  base64: string;
  mimeType: string;
  fileName: string;
  label?: string;
  detectedDamage?: {
    category: DamageCategory;
    confidence: number;
    observations: string;
  };
}

export interface LineItem {
  id: string;
  code: string;
  description: string;
  quantity: number;
  unit: string;
  roomName: string;
  justification?: string;
}

export interface EstimationState {
  carrier: string;
  synopsis: string;
  platform: Platform;
  guidelinesUrl?: string;
  customGuidelines?: string;
  uploadedGuidelineName?: string;
  rooms: Room[];
  photos: Photo[];
  lineItems: LineItem[];
  isAnalyzing: boolean;
  analysisComplete: boolean;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
  Download,
  AlertCircle,
  Droplets,
  Flame,
  Construction,
  Sparkles,
  Info,
  ShieldCheck,
  Star,
  History,
  Search,
  Upload,
  ChevronDown,
  X
} from 'lucide-react';
import { Platform, Room, Photo, EstimationState, LineItem, DamageCategory } from './types';
import { fetchCarrierGuidelines, analyzeDamage } from './services/geminiService';

const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites'
};

const DamageIcon = ({ category }: { category?: DamageCategory }) => {
  switch (category) {
    case 'Water': return <Droplets className="text-blue-500" size={16} />;
    case 'Fire': return <Flame className="text-orange-500" size={16} />;
    case 'Structural': return <Construction className="text-red-500" size={16} />;
    case 'Cosmetic': return <Sparkles className="text-purple-500" size={16} />;
    default: return <Info className="text-slate-400" size={16} />;
  }
};

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [state, setState] = useState<EstimationState>({
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    photos: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    customGuidelines: '',
    uploadedGuidelineName: ''
  });

  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);
  const [guidelineMode, setGuidelineMode] = useState<'search' | 'upload'>('search');

  const dropdownRef = useRef<HTMLDivElement>(null);

  // Load history and favorites
  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);

    // Update history
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
  };

  const handleGuidelineUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setState(p => ({ 
        ...p, 
        customGuidelines: content, 
        uploadedGuidelineName: file.name 
      }));
    };
    reader.readAsText(file); // For simplicity, reading as text. In production, consider PDF parsing.
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const addRoom = (name: string, type: 'Room' | 'Exterior Face') => {
    const newRoom: Room = { id: crypto.randomUUID(), name, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const removeRoom = (id: string) => {
    setState(prev => ({ 
      ...prev, 
      rooms: prev.rooms.filter(r => r.id !== id),
      photos: prev.photos.filter(p => p.roomId !== id)
    }));
  };

  const handleFileUpload = (roomId: string, files: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const base64 = e.target?.result as string;
        const newPhoto: Photo = {
          id: crypto.randomUUID(),
          roomId,
          base64,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, photos: [...prev.photos, newPhoto] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const handleFetchGuidelines = async () => {
    if (!state.carrier) return;
    setGuidelinesLoading(true);
    const g = await fetchCarrierGuidelines(state.carrier);
    setFetchedGuidelines(g);
    setGuidelinesLoading(false);
  };

  const runAnalysis = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform,
        state.carrier,
        state.synopsis,
        state.customGuidelines || fetchedGuidelines,
        state.photos,
        roomMap
      );
      setState(prev => ({
        ...prev,
        lineItems: result.lineItems,
        photos: result.labeledPhotos,
        isAnalyzing: false,
        analysisComplete: true
      }));
      nextStep();
    } catch (err) {
      alert("Analysis failed. Please try again.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const filteredHistory = carrierHistory.filter(h => !carrierFavorites.includes(h));

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Header */}
      <header className="flex items-center justify-between mb-8 pb-4 border-b border-slate-200">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white">
            <ClipboardCheck size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">AdjusterAI</h1>
            <p className="text-sm text-slate-500 font-medium">Smart Repair Estimator</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1">
            {[1, 2, 3, 4, 5].map(i => (
              <div 
                key={i} 
                className={`h-2 w-8 rounded-full transition-colors ${i <= step ? 'bg-indigo-600' : 'bg-slate-200'}`}
              />
            ))}
          </div>
          <span className="text-xs font-bold text-slate-400 uppercase">Step {step} of 5</span>
        </div>
      </header>

      {/* Step 1: Initial Setup */}
      {step === 1 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
          <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
            <Building2 className="text-indigo-600" />
            Project Fundamentals
          </h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-6">
              {/* Carrier Selection */}
              <div className="relative" ref={dropdownRef}>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Insurance Carrier</label>
                <div 
                  className="flex items-center justify-between px-4 py-2.5 border border-slate-300 rounded-lg bg-white cursor-pointer hover:border-indigo-500 transition-all shadow-sm"
                  onClick={() => setIsCarrierDropdownOpen(!isCarrierDropdownOpen)}
                >
                  <span className={state.carrier ? "text-slate-900 font-medium" : "text-slate-400"}>
                    {state.carrier || "Select or Type Carrier..."}
                  </span>
                  <ChevronDown className={`text-slate-400 transition-transform ${isCarrierDropdownOpen ? 'rotate-180' : ''}`} size={18} />
                </div>

                {isCarrierDropdownOpen && (
                  <div className="absolute z-50 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-100">
                    <div className="p-2 border-b border-slate-100">
                      <input 
                        autoFocus
                        type="text"
                        placeholder="Type to search or add..."
                        className="w-full px-3 py-2 text-sm bg-slate-50 rounded-md border-none focus:ring-2 focus:ring-indigo-500 outline-none"
                        value={state.carrier}
                        onChange={(e) => setState(p => ({ ...p, carrier: e.target.value }))}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter' && state.carrier) selectCarrier(state.carrier);
                        }}
                      />
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {/* Favorites */}
                      {carrierFavorites.length > 0 && (
                        <div className="p-2">
                          <p className="px-2 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Favorites</p>
                          {carrierFavorites.map(fav => (
                            <div 
                              key={fav}
                              className="group flex items-center justify-between px-3 py-2 hover:bg-indigo-50 rounded-lg cursor-pointer transition-colors"
                              onClick={() => selectCarrier(fav)}
                            >
                              <div className="flex items-center gap-3">
                                <Star className="text-amber-400 fill-amber-400" size={14} />
                                <span className="text-sm font-medium text-slate-700">{fav}</span>
                              </div>
                              <button onClick={(e) => toggleFavorite(e, fav)} className="opacity-0 group-hover:opacity-100">
                                <X size={14} className="text-slate-400" />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                      {/* History */}
                      {filteredHistory.length > 0 && (
                        <div className="p-2 border-t border-slate-50">
                          <p className="px-2 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Recent</p>
                          {filteredHistory.map(hist => (
                            <div 
                              key={hist}
                              className="group flex items-center justify-between px-3 py-2 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors"
                              onClick={() => selectCarrier(hist)}
                            >
                              <div className="flex items-center gap-3 text-slate-500">
                                <History size={14} />
                                <span className="text-sm">{hist}</span>
                              </div>
                              <button onClick={(e) => toggleFavorite(e, hist)} className="opacity-0 group-hover:opacity-100 p-1 hover:bg-white rounded">
                                <Star className="text-slate-300 hover:text-amber-400" size={14} />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                      {state.carrier && !carrierHistory.includes(state.carrier) && (
                        <div 
                          className="p-3 bg-indigo-50 hover:bg-indigo-100 cursor-pointer text-indigo-700 text-sm font-bold flex items-center gap-2"
                          onClick={() => selectCarrier(state.carrier)}
                        >
                          <Plus size={16} /> Add "{state.carrier}"
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>

              {/* Guidelines Box */}
              <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 space-y-4">
                <div className="flex items-center justify-between">
                  <label className="text-sm font-semibold text-slate-700">Repair Guidelines</label>
                  <div className="flex bg-slate-200 p-1 rounded-lg">
                    <button 
                      onClick={() => setGuidelineMode('search')}
                      className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-bold transition-all ${guidelineMode === 'search' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                      <Search size={14} /> Auto Search
                    </button>
                    <button 
                      onClick={() => setGuidelineMode('upload')}
                      className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-bold transition-all ${guidelineMode === 'upload' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                      <Upload size={14} /> Manual Upload
                    </button>
                  </div>
                </div>

                {guidelineMode === 'search' ? (
                  <div className="space-y-3">
                    <p className="text-xs text-slate-500">AI will search the internet for {state.carrier || 'the carrier'}'s latest repair standards.</p>
                    <button 
                      onClick={handleFetchGuidelines}
                      disabled={!state.carrier || guidelinesLoading}
                      className="w-full py-2.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-lg text-sm font-bold flex items-center justify-center gap-2 shadow-sm"
                    >
                      {guidelinesLoading ? <Loader2 className="animate-spin" size={18} /> : <Search size={18} />}
                      Fetch Carrier Guidelines
                    </button>
                  </div>
                ) : (
                  <div className="space-y-3">
                    <p className="text-xs text-slate-500">Upload a PDF or text file containing carrier-specific pricing or repair rules.</p>
                    <label className="flex flex-col items-center justify-center w-full py-4 border-2 border-dashed border-slate-300 rounded-lg cursor-pointer hover:bg-slate-100 transition-colors">
                      {state.uploadedGuidelineName ? (
                        <div className="flex items-center gap-2 text-indigo-600 font-bold text-sm">
                          <CheckCircle2 size={18} />
                          {state.uploadedGuidelineName}
                        </div>
                      ) : (
                        <div className="flex flex-col items-center gap-1 text-slate-400">
                          <Upload size={24} />
                          <span className="text-xs font-bold">Select Guideline File</span>
                        </div>
                      )}
                      <input type="file" className="hidden" accept=".pdf,.txt,.doc" onChange={handleGuidelineUpload} />
                    </label>
                  </div>
                )}

                {(fetchedGuidelines || state.customGuidelines) && (
                  <div className="p-3 bg-white border border-slate-100 rounded-lg shadow-inner">
                    <h3 className="text-[10px] font-bold text-slate-400 uppercase mb-1">Active Guideline Context</h3>
                    <p className="text-xs text-slate-600 italic line-clamp-2">
                      {state.customGuidelines ? "Custom upload active: " + state.uploadedGuidelineName : fetchedGuidelines}
                    </p>
                  </div>
                )}
              </div>

              {/* Estimating Platform */}
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Target Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    onClick={() => setState(p => ({ ...p, platform: Platform.XACTIMATE }))}
                    className={`py-3 px-4 rounded-xl border-2 text-center font-bold transition-all ${state.platform === Platform.XACTIMATE ? 'border-indigo-600 bg-indigo-50 text-indigo-600 shadow-sm' : 'border-slate-200 bg-white text-slate-400'}`}
                  >
                    Xactimate
                  </button>
                  <button 
                    onClick={() => setState(p => ({ ...p, platform: Platform.SYMBILITY }))}
                    className={`py-3 px-4 rounded-xl border-2 text-center font-bold transition-all ${state.platform === Platform.SYMBILITY ? 'border-indigo-600 bg-indigo-50 text-indigo-600 shadow-sm' : 'border-slate-200 bg-white text-slate-400'}`}
                  >
                    Symbility
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <label className="block text-sm font-semibold text-slate-700">Damage Synopsis & Site Notes</label>
              <textarea 
                rows={12}
                placeholder="Describe the scope of damage (e.g., 'Category 3 water intrusion from roof leak affecting ceiling and north wall of living room. Water observed at 3 inches on drywall. Baseboards show separation...')"
                className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none resize-none transition-shadow hover:shadow-inner bg-slate-50/30"
                value={state.synopsis}
                onChange={e => setState(p => ({ ...p, synopsis: e.target.value }))}
              />
              <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 flex gap-3">
                <AlertCircle className="text-amber-500 shrink-0" size={20} />
                <p className="text-xs text-amber-800 leading-relaxed">
                  <strong>Pro Tip:</strong> Detail specific measurements and material types (e.g. 'Stipple ceiling', 'Engineered hardwood') to improve AI line item accuracy.
                </p>
              </div>
            </div>
          </div>

          <div className="mt-8 flex justify-end">
            <button 
              onClick={nextStep}
              disabled={!state.carrier || !state.synopsis}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-3 rounded-lg font-bold flex items-center gap-2 transition-all shadow-md active:scale-95"
            >
              Next: Define Structure
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Structure/Diagram */}
      {step === 2 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold flex items-center gap-2">
              <Building2 className="text-indigo-600" />
              Define Rooms & Structure Faces
            </h2>
            <div className="flex gap-2">
              <button 
                onClick={() => addRoom(`Room ${state.rooms.length + 1}`, 'Room')}
                className="px-4 py-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 rounded-lg text-sm font-bold flex items-center gap-2"
              >
                <Plus size={16} /> Add Room
              </button>
              <button 
                onClick={() => addRoom(`Elevation ${state.rooms.length + 1}`, 'Exterior Face')}
                className="px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-bold flex items-center gap-2"
              >
                <Plus size={16} /> Add Exterior Face
              </button>
            </div>
          </div>

          {state.rooms.length === 0 ? (
            <div className="text-center py-20 border-2 border-dashed border-slate-200 rounded-2xl">
              <p className="text-slate-400 font-medium">No rooms defined. Add your first room or elevation to start uploading photos.</p>
            </div>
          ) : (
