export type DamageCategory = 'Water' | 'Fire' | 'Structural' | 'Cosmetic' | 'Mold/Microbial' | 'Unknown';

export type EvidenceType = 'Photo' | 'PDF Package' | 'Scope Sheet' | 'Measurement Report' | 'Technical Document';

