import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Platform, EvidenceItem, LineItem, DamageCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchCarrierGuidelines = async (carrier: string): Promise<string> => {
  const prompt = `Find the 2024-2025 property estimating and repair guidelines for the insurance carrier: ${carrier}. 
  Focus on technical requirements for water mitigation, fire remediation, and structural repairs. 
  Summarize key rules for material waste, overhead and profit, and mandatory line items.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    return response.text || "No specific guidelines found via search.";
  } catch (error) {
    console.error("Error fetching guidelines:", error);
    return "Error retrieving carrier guidelines.";
  }
};

export const analyzeDamage = async (
  platform: Platform,
  carrier: string,
  synopsis: string,
  guidelines: string,
  evidence: EvidenceItem[],
  rooms: { [id: string]: string }
): Promise<{ lineItems: LineItem[]; labeledEvidence: EvidenceItem[] }> => {

  const mediaParts = evidence.map(item => ({
    inlineData: {
      data: item.base64.split(',')[1] || item.base64,
      mimeType: item.mimeType
    }
  }));

  const prompt = `
    You are an expert Forensic Insurance Adjuster and Estimator.
    Platform: ${platform}
    Carrier: ${carrier}
    Carrier Guidelines: ${guidelines}
    Claim Synopsis: ${synopsis}

    INPUT TYPES:
    You are receiving a mix of visual evidence (photos) and technical documentation (Eagleview measurement reports, Hover reports, hand-written scope sheets, or PDF photo packages).

    TASK:
    1. Cross-Reference: Extract measurements and structure details from reports (Eagleview/Hover) and use them to quantify the damage seen in photos.
    2. Damage Detection: For photos, identify category (Water, Fire, Structural, Cosmetic, Mold).
    3. Technical Reasoning: Synthesize report data (e.g., roof pitch, wall area) with photo evidence (e.g., missing shingles, wet drywall) to create an accurate scope.
    4. Line Item Generation: Produce ${platform} line items. Include 'justification' explaining the synthesis of document data and visual evidence.
    5. Labeling: Create professional labels for visual evidence.

    OUTPUT SCHEMA REQUIREMENTS:
    Return valid JSON. Match every item in the input evidence to a result in evidenceResults.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { 
        parts: [
          ...mediaParts, 
          { text: prompt + `\n\nInput Item IDs (in order): ${evidence.map(e => e.id).join(', ')}` }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            lineItems: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  code: { type: Type.STRING },
                  description: { type: Type.STRING },
                  quantity: { type: Type.NUMBER },
                  unit: { type: Type.STRING },
                  roomName: { type: Type.STRING },
                  justification: { type: Type.STRING }
                },
                required: ["code", "description", "quantity", "unit", "roomName", "justification"]
              }
            },
            evidenceResults: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  label: { type: Type.STRING },
                  damageCategory: { type: Type.STRING },
                  confidence: { type: Type.NUMBER },
                  observations: { type: Type.STRING }
                },
                required: ["id", "label"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || '{}');

    const labeledEvidence = evidence.map(e => {
      const match = result.evidenceResults?.find((res: any) => res.id === e.id);
      return { 
        ...e, 
        label: match?.label || "Documentation/Evidence",
        detectedDamage: match?.damageCategory ? {
          category: match.damageCategory as DamageCategory,
          confidence: match.confidence || 0,
          observations: match.observations || "Document review complete."
        } : undefined
      };
    });

    return {
      lineItems: result.lineItems.map((li: any, index: number) => ({ ...li, id: `li-${index}` })),
      labeledEvidence
    };
  } catch (error) {
    console.error("Advanced AI Documentation Analysis Error:", error);
    throw error;
  }
};

