              <label className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-slate-200 rounded-2xl cursor-pointer hover:bg-slate-50 transition-all group">
                {state.fileA ? (
                  <div className="flex flex-col items-center gap-2 text-indigo-600">
                    <CheckCircle2 size={32} />
                    <span className="text-xs font-black truncate max-w-[150px]">{state.fileA.fileName}</span>
                  </div>
                ) : (
                  <>
                    <Upload className="text-slate-300 group-hover:text-indigo-400 mb-2" size={32} />
                    <span className="text-xs font-bold text-slate-400">Upload ESX, XML or PDF</span>
                  </>
                )}
                <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleFileUpload('A', e.target.files[0])} />
              </label>
            </div>
            {/* Estimate B */}
            <div className="space-y-4">
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest">Estimate B (Comparison)</label>
              <select 
                className="w-full px-4 py-2 border rounded-xl mb-2 text-sm font-bold bg-slate-50"
