                    <button onClick={() => setGuidelineMode('upload')} className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${guidelineMode === 'upload' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>Upload</button>
                  </div>
                </div>
                {guidelineMode === 'search' ? (
                  <button onClick={async () => {
                    setGuidelinesLoading(true);
                    const g = await fetchCarrierGuidelines(state.carrier);
