                <Plus size={14} /> Add Room
              </button>
              <button onClick={() => addRoom(`Elevation ${state.rooms.length + 1}`, 'Exterior Face')} className="px-6 py-2.5 bg-slate-50 text-slate-700 hover:bg-slate-100 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all">
