        <div className="flex bg-slate-200/50 p-1.5 rounded-2xl shadow-inner backdrop-blur-sm">
          <button 
            onClick={() => handleModeToggle(AppMode.INVESTIGATION)}
            className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.INVESTIGATION ? 'bg-white shadow-lg text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
