            className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.COMPARISON ? 'bg-white shadow-lg text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
