          <div className="grid lg:grid-cols-5 gap-10">
            <div className="lg:col-span-2 space-y-8">
               <h2 className="text-xl font-black px-4 text-slate-800 uppercase">Evidence Log</h2>
               <div className="space-y-8 max-h-[1200px] overflow-auto pr-6 custom-scrollbar">
                  {state.evidence.map(item => (
                    <div key={item.id} className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
                       <div className="relative aspect-video bg-slate-50">
                          {item.mimeType.includes('image') ? <img src={item.base64} alt="Evidence" className="w-full h-full object-cover" /> : <div className="w-full h-full flex flex-col items-center justify-center"><FileSearch className="text-indigo-200" size={48} /></div>}
                          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                            <div className="px-4 py-1.5 bg-black/70 backdrop-blur rounded-xl text-[9px] font-black text-white uppercase tracking-widest">{state.rooms.find(r => r.id === item.roomId)?.name || "Global Document"}</div>
                          </div>
                       </div>
                       <div className="p-6 space-y-4">
                          <p className="text-sm text-slate-700 leading-relaxed font-bold tracking-tight">{item.detectedDamage?.observations}</p>
                          <div className="pt-4 border-t border-slate-50"><p className="text-sm text-indigo-900 italic font-black">{item.label}</p></div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
            <div className="lg:col-span-3">
               <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 flex flex-col h-full overflow-hidden">
                  <div className="p-8 border-b bg-slate-50/50 flex items-center justify-between">
                     <h2 className="text-xl font-black text-slate-800 uppercase">Generated Scope</h2>
                     <button className="text-white bg-indigo-600 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase shadow-lg hover:bg-indigo-700 transition-all">Download {state.platform}</button>
                  </div>
                  <div className="flex-1 p-8 space-y-10">
                     {state.rooms.map(room => {
                        const roomItems = state.lineItems.filter(li => li.roomName === room.name);
                        if (roomItems.length === 0) return null;
                        return (
                          <div key={room.id} className="animate-in fade-in slide-in-from-left-4 duration-700">
                             <div className="flex items-center gap-3 mb-6"><div className="h-5 w-1.5 bg-indigo-500 rounded-full"></div><h3 className="font-black text-slate-800 text-sm uppercase tracking-widest">{room.name}</h3></div>
                             <div className="grid gap-4">
                                {roomItems.map(item => (
                                  <div key={item.id} className="p-6 border border-slate-50 rounded-3xl bg-slate-50/30 hover:bg-white transition-all group">
                                     <div className="flex items-start justify-between gap-6 mb-4">
                                        <div className="flex items-center gap-3"><span className="font-mono text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-lg border border-indigo-100 tracking-tighter">{item.code}</span><span className="font-black text-slate-900">{item.description}</span></div>
                                        <div className="text-right shrink-0"><p className="text-lg font-black text-indigo-600 tracking-tighter">{item.quantity} {item.unit}</p></div>
                                     </div>
                                     <div className="flex items-start gap-4 text-slate-500 bg-white p-4 rounded-2xl border border-slate-50 text-[11px] leading-relaxed shadow-sm"><Info size={16} className="mt-0.5 shrink-0 text-indigo-300" /><span><strong className="text-indigo-600 uppercase text-[9px] font-black mr-1">Justification:</strong> {item.justification}</span></div>
                                  </div>
                                ))}
                             </div>
                          </div>
                        );
                     })}
                  </div>
               </div>
            </div>
          </div>
          <div className="flex justify-center pt-10 pb-20"><button onClick={() => window.location.reload()} className="px-16 py-6 bg-slate-900 text-white rounded-3xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all shadow-2xl active:scale-95">Start New Investigation</button></div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Universal Header */}
      <header className="flex flex-col md:flex-row items-center justify-between mb-12 pb-6 border-b border-slate-200 gap-6">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-2xl text-white shadow-xl shadow-indigo-200"><ClipboardCheck size={32} /></div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none">AdjusterAI</h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1.5">Enterprise Estimating Suite</p>
          </div>
        </div>

        <div className="flex bg-slate-200/50 p-1.5 rounded-2xl shadow-inner backdrop-blur-sm">
          <button onClick={() => handleModeToggle(AppMode.INVESTIGATION)} className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.INVESTIGATION ? 'bg-white shadow-lg text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Investigation</button>
          <button onClick={() => handleModeToggle(AppMode.COMPARISON)} className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.COMPARISON ? 'bg-white shadow-lg text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Comparison</button>
        </div>

        <div className="hidden lg:flex items-center gap-6">
           <div className="flex items-center gap-2"><Zap size={14} className="text-amber-500 fill-amber-500" /><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gemini 3.0 Pro</span></div>
           <div className="h-4 w-px bg-slate-200"></div>
           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Build 2.5.4</span>
        </div>
      </header>

      <main className="min-h-[600px]">
        {state.mode === AppMode.COMPARISON ? renderComparisonFlow() : renderInvestigationFlow()}
      </main>

      {/* Camera Capture Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border border-white/10">
            <video ref={videoRef} autoPlay playsInline className="w-full aspect-[4/3] object-cover" />
            <canvas ref={canvasRef} className="hidden" />

            <div className="p-6 flex items-center justify-between bg-slate-800">
               <button onClick={stopCamera} className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all"><X size={24} /></button>
               <button onClick={capturePhoto} className="group relative">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center transition-all group-active:scale-90 group-hover:scale-110">
                    <div className="w-14 h-14 border-4 border-slate-800 rounded-full" />
                  </div>
               </button>
               <div className="w-12 h-12" /> {/* Spacer */}
            </div>

            <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 border border-white/10">
               <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
               <span className="text-[10px] font-black text-white uppercase tracking-widest">Live: {state.rooms.find(r => r.id === cameraRoomId)?.name || 'General'}</span>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-20 pt-10 border-t border-slate-200 text-center space-y-3 pb-12">
        <p className="text-xs text-slate-400 font-medium tracking-tight">© 2024 AdjusterAI. Symbility and Cotality mapping active.</p>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
  Download,
  AlertCircle,
  Droplets,
  Flame,
  Construction,
  Sparkles,
  Info,
  ShieldCheck,
  Star,
  History,
  Search,
  Upload,
  ChevronDown,
  X,
  FileSearch,
  Map,
  Files,
  ArrowRightLeft,
  TrendingDown,
  TrendingUp,
  Minus,
  LayoutGrid,
  Zap,
  Shield,
  Maximize,
  Image as ImageIcon
} from 'lucide-react';
import { Platform, Room, EvidenceItem, EstimationState, LineItem, DamageCategory, EvidenceType, AppMode, ComparisonResult } from './types';
import { fetchCarrierGuidelines, analyzeDamage, compareEstimates } from './services/geminiService';

const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites'
};

const DamageIcon = ({ category }: { category?: DamageCategory }) => {
  switch (category) {
    case 'Water': return <Droplets className="text-blue-500" size={16} />;
    case 'Fire': return <Flame className="text-orange-500" size={16} />;
    case 'Structural': return <Construction className="text-red-500" size={16} />;
    case 'Cosmetic': return <Sparkles className="text-purple-500" size={16} />;
    default: return <Info className="text-slate-400" size={16} />;
  }
};

const EvidenceTypeIcon = ({ type }: { type: EvidenceType }) => {
  switch (type) {
    case 'Photo': return <ImageIcon size={16} />;
    case 'PDF Package': return <Files size={16} />;
    case 'Measurement Report': return <Map size={16} />;
    case 'Scope Sheet': return <ClipboardCheck size={16} />;
    default: return <FileText size={16} />;
  }
};

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [state, setState] = useState<EstimationState>({
    mode: AppMode.INVESTIGATION,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);
  const [guidelineMode, setGuidelineMode] = useState<'search' | 'upload'>('search');

  // Camera state
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filter carrier lists based on the current search input in state.carrier
  const filteredFavorites = carrierFavorites.filter(fav => 
    fav.toLowerCase().includes(state.carrier.toLowerCase())
  );
  const filteredHistory = carrierHistory.filter(hist => 
    hist.toLowerCase().includes(state.carrier.toLowerCase()) && !carrierFavorites.includes(hist)
  );

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ 
      ...prev, 
      mode, 
      analysisComplete: false, 
      isAnalyzing: false, 
      evidence: [], 
      lineItems: [], 
      comparisonResult: undefined 
    }));
    setStep(1);
  };

  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraRoomId(roomId);
        setIsCameraOpen(true);
      }
    } catch (err) {
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
    setCameraRoomId(undefined);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId: cameraRoomId,
          type: 'Photo',
          base64,
          mimeType: 'image/jpeg',
          fileName: `capture_${Date.now()}.jpg`
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  const handleComparisonFileUpload = (side: 'A' | 'B', file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = e.target?.result as string;
      const evidence: EvidenceItem = {
        id: crypto.randomUUID(),
        type: 'Estimate File',
        base64,
        mimeType: file.type || 'application/octet-stream',
        fileName: file.name
      };
      setState(prev => ({ ...prev, [side === 'A' ? 'fileA' : 'fileB']: evidence }));
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!state.fileA || !state.fileB) {
      alert("Please upload both Estimate A and Estimate B before running comparison.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const result = await compareEstimates(state.fileA, state.fileB, state.platformA, state.platformB);
      setState(prev => ({ ...prev, comparisonResult: result, isAnalyzing: false, analysisComplete: true }));
      setStep(3);
    } catch (err) {
      alert("Comparison analysis failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
  };

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const addRoom = (name: string, type: 'Room' | 'Exterior Face') => {
    const newRoom: Room = { id: crypto.randomUUID(), name, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId,
          type,
          base64: e.target?.result as string,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const runInvestigationAnalysis = async () => {
    if (state.evidence.length === 0) {
      alert("Please upload evidence (photos or reports) before running analysis.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform, 
        state.carrier || "Unknown Carrier", 
        state.synopsis || "No synopsis provided", 
        fetchedGuidelines || state.customGuidelines || "Standard industry rules", 
        state.evidence, 
        roomMap
      );
      setState(prev => ({ 
        ...prev, 
        lineItems: result.lineItems, 
        evidence: result.labeledEvidence, 
        isAnalyzing: false, 
        analysisComplete: true 
      }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const renderComparisonFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white rounded-3xl shadow-xl p-8 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-5xl mx-auto border border-slate-200">
          <div className="text-center mb-10">
            <h2 className="text-2xl font-black text-slate-800 mb-2 flex items-center justify-center gap-3">
              <ArrowRightLeft className="text-indigo-600" size={32} />
              Comparative Estimate Analysis
            </h2>
            <p className="text-slate-500 font-medium">Identify line item variances and financial discrepancies between platforms.</p>
          </div>

          <div className="grid md:grid-cols-2 gap-10 mb-10">
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Estimate A (Baseline)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 rounded-2xl text-sm font-bold bg-slate-50 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformA}
                  onChange={e => setState(p => ({ ...p, platformA: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 rounded-3xl cursor-pointer hover:bg-slate-50 transition-all group relative overflow-hidden">
                  {state.fileA ? (
                    <div className="flex flex-col items-center gap-3 text-indigo-600">
                      <div className="bg-indigo-100 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full">{state.fileA.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileA: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 group-hover:text-indigo-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('A', e.target.files[0])} />
                </label>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Estimate B (Comparison)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 rounded-2xl text-sm font-bold bg-slate-50 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformB}
                  onChange={e => setState(p => ({ ...p, platformB: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 rounded-3xl cursor-pointer hover:bg-slate-50 transition-all group relative overflow-hidden">
                  {state.fileB ? (
                    <div className="flex flex-col items-center gap-3 text-amber-600">
                      <div className="bg-amber-100 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full">{state.fileB.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileB: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 group-hover:text-amber-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('B', e.target.files[0])} />
                </label>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center gap-4">
            <button 
              onClick={runComparison}
              disabled={state.isAnalyzing}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-16 py-5 rounded-3xl font-black text-sm uppercase tracking-widest shadow-2xl shadow-indigo-200 flex items-center gap-4 transition-all active:scale-95"
            >
              {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Mapping Variances...</> : <><Zap size={20} className="fill-white" /> Perform Cross-Platform Audit</>}
            </button>
          </div>
        </div>
      );
    }

    if (step === 3 && state.comparisonResult) {
      const res = state.comparisonResult;
      return (
        <div className="space-y-8 animate-in fade-in duration-700 max-w-6xl mx-auto">
          <div className="grid md:grid-cols-4 gap-6">
             <div className="md:col-span-2 bg-slate-900 text-white p-8 rounded-3xl shadow-2xl flex flex-col justify-between">
                <div>
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Executive Variance Analysis</h3>
                  <div className="flex items-center gap-8">
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est A Total</p>
                      <p className="text-3xl font-black">${res.summary.total.a.toLocaleString()}</p>
                    </div>
                    <ArrowRightLeft className="text-indigo-400" />
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est B Total</p>
                      <p className="text-3xl font-black">${res.summary.total.b.toLocaleString()}</p>
                    </div>
                  </div>
                </div>
