const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites',
  THEME: 'adjuster_ai_theme'
};

const DamageIcon = ({ category }: { category?: DamageCategory }) => {
  switch (category) {
    case 'Water': return <Droplets className="text-blue-500" size={16} />;
    case 'Fire': return <Flame className="text-orange-500" size={16} />;
    case 'Structural': return <Construction className="text-red-500" size={16} />;
    case 'Cosmetic': return <Sparkles className="text-purple-500" size={16} />;
    default: return <Info className="text-slate-400 dark:text-slate-500" size={16} />;
  }
};

const EvidenceTypeIcon = ({ type }: { type: EvidenceType }) => {
  switch (type) {
    case 'Photo': return <ImageIcon size={16} />;
    case 'PDF Package': return <Files size={16} />;
    case 'Measurement Report': return <Map size={16} />;
    case 'Scope Sheet': return <ClipboardCheck size={16} />;
    default: return <FileText size={16} />;
  }
};

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.THEME);
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [state, setState] = useState<EstimationState>({
    mode: AppMode.INVESTIGATION,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);
  const [guidelineMode, setGuidelineMode] = useState<'search' | 'upload'>('search');

  // Camera state
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // Filter carrier lists based on the current search input in state.carrier
  const filteredFavorites = carrierFavorites.filter(fav => 
    fav.toLowerCase().includes(state.carrier.toLowerCase())
  );
  const filteredHistory = carrierHistory.filter(hist => 
    hist.toLowerCase().includes(state.carrier.toLowerCase()) && !carrierFavorites.includes(hist)
  );

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ 
      ...prev, 
      mode, 
      analysisComplete: false, 
      isAnalyzing: false, 
      evidence: [], 
      lineItems: [], 
      comparisonResult: undefined 
    }));
    setStep(1);
  };

  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraRoomId(roomId);
        setIsCameraOpen(true);
      }
    } catch (err) {
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
    setCameraRoomId(undefined);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId: cameraRoomId,
          type: 'Photo',
          base64,
          mimeType: 'image/jpeg',
          fileName: `capture_${Date.now()}.jpg`
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  const handleComparisonFileUpload = (side: 'A' | 'B', file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = e.target?.result as string;
      const evidence: EvidenceItem = {
        id: crypto.randomUUID(),
        type: 'Estimate File',
        base64,
        mimeType: file.type || 'application/octet-stream',
        fileName: file.name
      };
      setState(prev => ({ ...prev, [side === 'A' ? 'fileA' : 'fileB']: evidence }));
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!state.fileA || !state.fileB) {
      alert("Please upload both Estimate A and Estimate B before running comparison.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const result = await compareEstimates(state.fileA, state.fileB, state.platformA, state.platformB);
      setState(prev => ({ ...prev, comparisonResult: result, isAnalyzing: false, analysisComplete: true }));
      setStep(3);
    } catch (err) {
      alert("Comparison analysis failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
  };

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const addRoom = (name: string, type: 'Room' | 'Exterior Face') => {
    const newRoom: Room = { id: crypto.randomUUID(), name, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId,
          type,
          base64: e.target?.result as string,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const runInvestigationAnalysis = async () => {
    const isRoofing = state.synopsis?.toLowerCase().includes('roof');
    const hasDetailedSynopsis = (state.synopsis?.length || 0) > 100;

    if (state.evidence.length === 0 && !hasDetailedSynopsis) {
      alert("Please provide either a detailed synopsis or upload evidence (photos/reports) before running analysis.");
      return;
    }

    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform, 
        state.carrier || "Unknown Carrier", 
        state.synopsis || "No synopsis provided", 
        fetchedGuidelines || state.customGuidelines || "Standard industry rules", 
        state.evidence, 
        roomMap
      );
      setState(prev => ({ 
        ...prev, 
        lineItems: result.lineItems, 
        evidence: result.labeledEvidence, 
        isAnalyzing: false, 
        analysisComplete: true 
      }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const renderComparisonFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-5xl mx-auto border border-slate-200 dark:border-slate-800">
          <div className="text-center mb-10">
            <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100 mb-2 flex items-center justify-center gap-3">
              <ArrowRightLeft className="text-indigo-600 dark:text-indigo-400" size={32} />
              Comparative Estimate Analysis
            </h2>
            <p className="text-slate-500 dark:text-slate-400 font-medium">Identify line item variances and financial discrepancies between platforms.</p>
          </div>

          <div className="grid md:grid-cols-2 gap-10 mb-10">
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate A (Baseline)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformA}
                  onChange={e => setState(p => ({ ...p, platformA: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group relative overflow-hidden">
                  {state.fileA ? (
                    <div className="flex flex-col items-center gap-3 text-indigo-600 dark:text-indigo-400">
                      <div className="bg-indigo-100 dark:bg-indigo-900/30 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full text-slate-900 dark:text-slate-100">{state.fileA.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileA: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 dark:text-slate-600 group-hover:text-indigo-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400 dark:text-slate-500">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('A', e.target.files[0])} />
                </label>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate B (Comparison)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformB}
                  onChange={e => setState(p => ({ ...p, platformB: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group relative overflow-hidden">
                  {state.fileB ? (
                    <div className="flex flex-col items-center gap-3 text-amber-600 dark:text-amber-400">
                      <div className="bg-amber-100 dark:bg-amber-900/30 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full text-slate-900 dark:text-slate-100">{state.fileB.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileB: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 dark:text-slate-600 group-hover:text-amber-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400 dark:text-slate-500">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('B', e.target.files[0])} />
                </label>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center gap-4">
            <button 
              onClick={runComparison}
              disabled={state.isAnalyzing}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-16 py-5 rounded-3xl font-black text-sm uppercase tracking-widest shadow-2xl shadow-indigo-200 dark:shadow-indigo-900/20 flex items-center gap-4 transition-all active:scale-95"
            >
              {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Mapping Variances...</> : <><Zap size={20} className="fill-white" /> Perform Cross-Platform Audit</>}
            </button>
          </div>
        </div>
      );
    }

    if (step === 3 && state.comparisonResult) {
      const res = state.comparisonResult;
      return (
        <div className="space-y-8 animate-in fade-in duration-700 max-w-6xl mx-auto">
          <div className="grid md:grid-cols-4 gap-6">
             <div className="md:col-span-2 bg-slate-900 dark:bg-slate-800 text-white p-8 rounded-3xl shadow-2xl flex flex-col justify-between">
                <div>
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Executive Variance Analysis</h3>
                  <div className="flex items-center gap-8">
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est A Total</p>
                      <p className="text-3xl font-black">${res.summary.total.a.toLocaleString()}</p>
                    </div>
                    <ArrowRightLeft className="text-indigo-400" />
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est B Total</p>
                      <p className="text-3xl font-black">${res.summary.total.b.toLocaleString()}</p>
                    </div>
                  </div>
                </div>
                <div className={`mt-8 px-5 py-3 rounded-2xl font-black text-xl flex items-center justify-between ${res.summary.total.b - res.summary.total.a < 0 ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                   <span>Net Variance</span>
                   <span>{res.summary.total.b - res.summary.total.a > 0 ? '+' : ''}{(res.summary.total.b - res.summary.total.a).toLocaleString()}</span>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Labor Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.labor.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.labor.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.labor.b - res.summary.labor.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.labor.b - res.summary.labor.a > 0 ? '+' : ''}{(res.summary.labor.b - res.summary.labor.a).toLocaleString()}</div>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Material Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.material.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.material.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.material.b - res.summary.material.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.material.b - res.summary.material.a > 0 ? '+' : ''}{(res.summary.material.b - res.summary.material.a).toLocaleString()}</div>
                </div>
             </div>
          </div>
          <div className="grid lg:grid-cols-3 gap-8">
             <div className="lg:col-span-1 space-y-6">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg">
                   <h3 className="text-xs font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-widest mb-4 flex items-center gap-2"><ShieldCheck size={16}/> Professional Opinion</h3>
                   <div className="prose prose-slate dark:prose-invert prose-sm font-medium leading-relaxed text-slate-700 dark:text-slate-300 italic">"{res.narrative}"</div>
                </div>
             </div>
             <div className="lg:col-span-2">
                <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
                   <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-800/20">
                      <h3 className="text-sm font-black text-slate-800 dark:text-slate-200 uppercase tracking-widest flex items-center gap-2"><TrendingDown className="text-indigo-600 dark:text-indigo-400" size={18}/> Variance Grid</h3>
                   </div>
                   <div className="overflow-x-auto">
                      <table className="w-full text-left text-sm border-collapse">
                        <thead className="bg-slate-50/50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest text-[10px]">
                          <tr>
                            <th className="px-8 py-5">Category</th>
                            <th className="px-8 py-5">Mapping</th>
                            <th className="px-8 py-5 text-right">Delta</th>
                            <th className="px-8 py-5">Analysis</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                          {res.variances.map((v, i) => (
                            <tr key={i} className="hover:bg-indigo-50/30 dark:hover:bg-indigo-900/10 transition-all group">
                              <td className="px-8 py-6 align-top"><span className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-lg text-[9px] font-black text-slate-500 dark:text-slate-400 uppercase">{v.category}</span></td>
                              <td className="px-8 py-6 align-top">
                                <div className="space-y-1">
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemA || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                  <ArrowRightLeft size={10} className="text-slate-300 dark:text-slate-600" />
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemB || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                </div>
                              </td>
                              <td className={`px-8 py-6 text-right font-black align-top text-base ${v.delta < 0 ? 'text-red-500' : 'text-green-500'}`}>{v.delta > 0 ? '+' : ''}{v.delta.toLocaleString()}</td>
                              <td className="px-8 py-6 text-[11px] text-slate-500 dark:text-slate-400 italic leading-relaxed font-medium align-top">{v.reason}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                   </div>
                </div>
                <div className="mt-8 flex justify-center">
                   <button onClick={() => window.location.reload()} className="px-10 py-4 bg-slate-900 dark:bg-slate-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:-translate-y-1 transition-all">New Comparison</button>
                </div>
             </div>
          </div>
        </div>
      );
    }
    return null;
  };

  const renderInvestigationFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
          <h2 className="text-xl font-black mb-8 flex items-center gap-2 text-slate-800 dark:text-slate-100"><Building2 className="text-indigo-600 dark:text-indigo-400" /> Claim Investigation Details</h2>
          <div className="grid md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <div className="relative" ref={dropdownRef}>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Insurance Carrier</label>
                <div onClick={() => setIsCarrierDropdownOpen(!isCarrierDropdownOpen)} className="flex items-center justify-between px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50/50 dark:bg-slate-800/50 cursor-pointer hover:border-indigo-500 dark:hover:border-indigo-400 hover:bg-white dark:hover:bg-slate-800 transition-all shadow-sm">
                  <span className={state.carrier ? "text-slate-900 dark:text-slate-100 font-bold" : "text-slate-400 dark:text-slate-500"}>{state.carrier || "Select Carrier..."}</span>
                  <ChevronDown className={`text-slate-400 dark:text-slate-500 transition-transform ${isCarrierDropdownOpen ? 'rotate-180' : ''}`} size={18} />
                </div>
                {isCarrierDropdownOpen && (
                  <div className="absolute z-50 w-full mt-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden">
                    <div className="p-3 border-b dark:border-slate-800"><input autoFocus type="text" placeholder="Search..." className="w-full px-4 py-2 text-sm bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-xl outline-none" value={state.carrier} onChange={e => setState(p => ({ ...p, carrier: e.target.value }))} /></div>
                    <div className="max-h-64 overflow-y-auto p-2">
                       {filteredFavorites.map(fav => (
                         <div key={fav} className="group flex items-center justify-between px-3 py-2.5 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-xl cursor-pointer" onClick={() => selectCarrier(fav)}>
                           <div className="flex items-center gap-3"><Star className="text-amber-400 fill-amber-400" size={14} /><span className="text-sm font-bold text-slate-700 dark:text-slate-200">{fav}</span></div>
                           <button onClick={(e) => toggleFavorite(e, fav)} className="opacity-0 group-hover:opacity-100 p-1"><X size={14} className="text-slate-400" /></button>
                         </div>
                       ))}
                       {filteredHistory.map(hist => (
                        <div key={hist} className="group flex items-center justify-between px-3 py-2.5 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl cursor-pointer" onClick={() => selectCarrier(hist)}>
                          <div className="flex items-center gap-3 text-slate-500 dark:text-slate-400"><History size={14} /><span className="text-sm font-medium">{hist}</span></div>
                          <button onClick={(e) => toggleFavorite(e, hist)} className="opacity-0 group-hover:opacity-100 p-1"><Star size={14} className="text-slate-300 dark:text-slate-600" /></button>
                        </div>
                       ))}
                    </div>
