} from 'lucide-react';
import { Platform, Room, EvidenceItem, EstimationState, LineItem, DamageCategory, EvidenceType, AppMode, ComparisonResult } from './types';
import { fetchCarrierGuidelines, analyzeDamage, compareEstimates } from './services/geminiService';

const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites',
  THEME: 'adjuster_ai_theme'
};

const INTERIOR_LABELS = [
  'Bedroom', 'Bathroom', 'Kitchen', 'Living Room', 'Dining Room', 
  'Hallway', 'Garage', 'Basement', 'Attic', 'Laundry Room', 
  'Master Bedroom', 'Closet', 'Office'
];

const EXTERIOR_LABELS = [
  'Front Elevation', 'Rear Elevation', 'Left Elevation', 
  'Right Elevation', 'Roof', 'Fence', 'Detached Structure'
];

const DamageIcon = ({ category }: { category?: DamageCategory }) => {
  switch (category) {
    case 'Water': return <Droplets className="text-blue-500" size={16} />;
    case 'Fire': return <Flame className="text-orange-500" size={16} />;
    case 'Structural': return <Construction className="text-red-500" size={16} />;
    case 'Cosmetic': return <Sparkles className="text-purple-500" size={16} />;
    default: return <Info className="text-slate-400 dark:text-slate-500" size={16} />;
  }
};

const EvidenceTypeIcon = ({ type }: { type: EvidenceType }) => {
  switch (type) {
    case 'Photo': return <ImageIcon size={16} />;
    case 'PDF Package': return <Files size={16} />;
    case 'Measurement Report': return <Map size={16} />;
    case 'Scope Sheet': return <ClipboardCheck size={16} />;
    default: return <FileText size={16} />;
  }
};

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.THEME);
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [state, setState] = useState<EstimationState>({
    mode: AppMode.INVESTIGATION,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);
  const [guidelineMode, setGuidelineMode] = useState<'search' | 'upload'>('search');

  // Camera state
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // Filter carrier lists based on the current search input in state.carrier
  const filteredFavorites = carrierFavorites.filter(fav => 
    fav.toLowerCase().includes(state.carrier.toLowerCase())
  );
  const filteredHistory = carrierHistory.filter(hist => 
    hist.toLowerCase().includes(state.carrier.toLowerCase()) && !carrierFavorites.includes(hist)
  );

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ 
      ...prev, 
      mode, 
      analysisComplete: false, 
      isAnalyzing: false, 
      evidence: [], 
      lineItems: [], 
      comparisonResult: undefined 
    }));
    setStep(1);
  };

  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraRoomId(roomId);
        setIsCameraOpen(true);
      }
    } catch (err) {
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
    setCameraRoomId(undefined);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId: cameraRoomId,
          type: 'Photo',
          base64,
          mimeType: 'image/jpeg',
          fileName: `capture_${Date.now()}.jpg`
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  const handleComparisonFileUpload = (side: 'A' | 'B', file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = e.target?.result as string;
      const evidence: EvidenceItem = {
        id: crypto.randomUUID(),
        type: 'Estimate File',
        base64,
        mimeType: file.type || 'application/octet-stream',
        fileName: file.name
      };
      setState(prev => ({ ...prev, [side === 'A' ? 'fileA' : 'fileB']: evidence }));
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!state.fileA || !state.fileB) {
      alert("Please upload both Estimate A and Estimate B before running comparison.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const result = await compareEstimates(state.fileA, state.fileB, state.platformA, state.platformB);
      setState(prev => ({ ...prev, comparisonResult: result, isAnalyzing: false, analysisComplete: true }));
      setStep(3);
    } catch (err) {
      alert("Comparison analysis failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
  };

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const addRoom = (baseLabel: string, type: 'Room' | 'Exterior Face') => {
    const existingSameLabels = state.rooms.filter(r => r.name.startsWith(baseLabel));
    let nextName = baseLabel;

    if (existingSameLabels.length > 0) {
      // Find the highest number used for this label
      let maxNum = 0;
      existingSameLabels.forEach(r => {
        const match = r.name.match(new RegExp(`^${baseLabel}\\s*(\\d+)$`));
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        } else if (r.name === baseLabel) {
          if (maxNum === 0) maxNum = 1;
        }
      });
      nextName = `${baseLabel} ${maxNum + 1}`;
    }

    const newRoom: Room = { id: crypto.randomUUID(), name: nextName, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId,
          type,
          base64: e.target?.result as string,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const runInvestigationAnalysis = async () => {
    const isRoofing = state.synopsis?.toLowerCase().includes('roof');
    const hasDetailedSynopsis = (state.synopsis?.length || 0) > 100;

    if (state.evidence.length === 0 && !hasDetailedSynopsis) {
      alert("Please provide either a detailed synopsis or upload evidence (photos/reports) before running analysis.");
      return;
    }

    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform, 
        state.carrier || "Unknown Carrier", 
        state.synopsis || "No synopsis provided", 
        fetchedGuidelines || state.customGuidelines || "Standard industry rules", 
        state.evidence, 
        roomMap
      );
      setState(prev => ({ 
        ...prev, 
        lineItems: result.lineItems, 
        evidence: result.labeledEvidence, 
        isAnalyzing: false, 
        analysisComplete: true 
      }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const renderComparisonFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-5xl mx-auto border border-slate-200 dark:border-slate-800">
          <div className="text-center mb-10">
            <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100 mb-2 flex items-center justify-center gap-3">
              <ArrowRightLeft className="text-indigo-600 dark:text-indigo-400" size={32} />
              Comparative Estimate Analysis
            </h2>
            <p className="text-slate-500 dark:text-slate-400 font-medium">Identify line item variances and financial discrepancies between platforms.</p>
          </div>

          <div className="grid md:grid-cols-2 gap-10 mb-10">
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate A (Baseline)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformA}
                  onChange={e => setState(p => ({ ...p, platformA: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group relative overflow-hidden">
                  {state.fileA ? (
                    <div className="flex flex-col items-center gap-3 text-indigo-600 dark:text-indigo-400">
                      <div className="bg-indigo-100 dark:bg-indigo-900/30 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full text-slate-900 dark:text-slate-100">{state.fileA.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileA: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 dark:text-slate-600 group-hover:text-indigo-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400 dark:text-slate-500">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('A', e.target.files[0])} />
                </label>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate B (Comparison)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformB}
                  onChange={e => setState(p => ({ ...p, platformB: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group relative overflow-hidden">
                  {state.fileB ? (
                    <div className="flex flex-col items-center gap-3 text-amber-600 dark:text-amber-400">
                      <div className="bg-amber-100 dark:bg-amber-900/30 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full text-slate-900 dark:text-slate-100">{state.fileB.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileB: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 dark:text-slate-600 group-hover:text-amber-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400 dark:text-slate-500">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('B', e.target.files[0])} />
                </label>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center gap-4">
            <button 
              onClick={runComparison}
              disabled={state.isAnalyzing}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-16 py-5 rounded-3xl font-black text-sm uppercase tracking-widest shadow-2xl shadow-indigo-200 dark:shadow-indigo-900/20 flex items-center gap-4 transition-all active:scale-95"
            >
              {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Mapping Variances...</> : <><Zap size={20} className="fill-white" /> Perform Cross-Platform Audit</>}
            </button>
          </div>
        </div>
      );
    }

    if (step === 3 && state.comparisonResult) {
      const res = state.comparisonResult;
      return (
        <div className="space-y-8 animate-in fade-in duration-700 max-w-6xl mx-auto">
          <div className="grid md:grid-cols-4 gap-6">
             <div className="md:col-span-2 bg-slate-900 dark:bg-slate-800 text-white p-8 rounded-3xl shadow-2xl flex flex-col justify-between">
                <div>
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Executive Variance Analysis</h3>
                  <div className="flex items-center gap-8">
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est A Total</p>
                      <p className="text-3xl font-black">${res.summary.total.a.toLocaleString()}</p>
                    </div>
                    <ArrowRightLeft className="text-indigo-400" />
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est B Total</p>
                      <p className="text-3xl font-black">${res.summary.total.b.toLocaleString()}</p>
                    </div>
                  </div>
                </div>
                <div className={`mt-8 px-5 py-3 rounded-2xl font-black text-xl flex items-center justify-between ${res.summary.total.b - res.summary.total.a < 0 ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                   <span>Net Variance</span>
                   <span>{res.summary.total.b - res.summary.total.a > 0 ? '+' : ''}{(res.summary.total.b - res.summary.total.a).toLocaleString()}</span>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Labor Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.labor.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.labor.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.labor.b - res.summary.labor.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.labor.b - res.summary.labor.a > 0 ? '+' : ''}{(res.summary.labor.b - res.summary.labor.a).toLocaleString()}</div>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Material Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.material.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.material.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.material.b - res.summary.material.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.material.b - res.summary.material.a > 0 ? '+' : ''}{(res.summary.material.b - res.summary.material.a).toLocaleString()}</div>
                </div>
             </div>
          </div>
          <div className="grid lg:grid-cols-3 gap-8">
             <div className="lg:col-span-1 space-y-6">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg">
                   <h3 className="text-xs font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-widest mb-4 flex items-center gap-2"><ShieldCheck size={16}/> Professional Opinion</h3>
                   <div className="prose prose-slate dark:prose-invert prose-sm font-medium leading-relaxed text-slate-700 dark:text-slate-300 italic">"{res.narrative}"</div>
                </div>
             </div>
             <div className="lg:col-span-2">
                <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
                   <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-800/20">
                      <h3 className="text-sm font-black text-slate-800 dark:text-slate-200 uppercase tracking-widest flex items-center gap-2"><TrendingDown className="text-indigo-600 dark:text-indigo-400" size={18}/> Variance Grid</h3>
                   </div>
                   <div className="overflow-x-auto">
                      <table className="w-full text-left text-sm border-collapse">
                        <thead className="bg-slate-50/50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest text-[10px]">
                          <tr>
                            <th className="px-8 py-5">Category</th>
                            <th className="px-8 py-5">Mapping</th>
                            <th className="px-8 py-5 text-right">Delta</th>
                            <th className="px-8 py-5">Analysis</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                          {res.variances.map((v, i) => (
                            <tr key={i} className="hover:bg-indigo-50/30 dark:hover:bg-indigo-900/10 transition-all group">
                              <td className="px-8 py-6 align-top"><span className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-lg text-[9px] font-black text-slate-500 dark:text-slate-400 uppercase">{v.category}</span></td>
                              <td className="px-8 py-6 align-top">
                                <div className="space-y-1">
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemA || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                  <ArrowRightLeft size={10} className="text-slate-300 dark:text-slate-600" />
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemB || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                </div>
                              </td>
                              <td className={`px-8 py-6 text-right font-black align-top text-base ${v.delta < 0 ? 'text-red-500' : 'text-green-500'}`}>{v.delta > 0 ? '+' : ''}{v.delta.toLocaleString()}</td>
                              <td className="px-8 py-6 text-[11px] text-slate-500 dark:text-slate-400 italic leading-relaxed font-medium align-top">{v.reason}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                   </div>
                </div>
                <div className="mt-8 flex justify-center">
                   <button onClick={() => window.location.reload()} className="px-10 py-4 bg-slate-900 dark:bg-slate-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:-translate-y-1 transition-all">New Comparison</button>
                </div>
             </div>
          </div>
        </div>
      );
    }
    return null;
  };

  const renderInvestigationFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
          <h2 className="text-xl font-black mb-8 flex items-center gap-2 text-slate-800 dark:text-slate-100"><Building2 className="text-indigo-600 dark:text-indigo-400" /> Claim Investigation Details</h2>
          <div className="grid md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <div className="relative" ref={dropdownRef}>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Insurance Carrier</label>
                <div onClick={() => setIsCarrierDropdownOpen(!isCarrierDropdownOpen)} className="flex items-center justify-between px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50/50 dark:bg-slate-800/50 cursor-pointer hover:border-indigo-500 dark:hover:border-indigo-400 hover:bg-white dark:hover:bg-slate-800 transition-all shadow-sm">
                  <span className={state.carrier ? "text-slate-900 dark:text-slate-100 font-bold" : "text-slate-400 dark:text-slate-500"}>{state.carrier || "Select Carrier..."}</span>
                  <ChevronDown className={`text-slate-400 dark:text-slate-500 transition-transform ${isCarrierDropdownOpen ? 'rotate-180' : ''}`} size={18} />
                </div>
                {isCarrierDropdownOpen && (
                  <div className="absolute z-50 w-full mt-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden">
                    <div className="p-3 border-b dark:border-slate-800"><input autoFocus type="text" placeholder="Search..." className="w-full px-4 py-2 text-sm bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-xl outline-none" value={state.carrier} onChange={e => setState(p => ({ ...p, carrier: e.target.value }))} /></div>
                    <div className="max-h-64 overflow-y-auto p-2">
                       {filteredFavorites.map(fav => (
                         <div key={fav} className="group flex items-center justify-between px-3 py-2.5 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-xl cursor-pointer" onClick={() => selectCarrier(fav)}>
                           <div className="flex items-center gap-3"><Star className="text-amber-400 fill-amber-400" size={14} /><span className="text-sm font-bold text-slate-700 dark:text-slate-200">{fav}</span></div>
                           <button onClick={(e) => toggleFavorite(e, fav)} className="opacity-0 group-hover:opacity-100 p-1"><X size={14} className="text-slate-400" /></button>
                         </div>
                       ))}
                       {filteredHistory.map(hist => (
                        <div key={hist} className="group flex items-center justify-between px-3 py-2.5 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl cursor-pointer" onClick={() => selectCarrier(hist)}>
                          <div className="flex items-center gap-3 text-slate-500 dark:text-slate-400"><History size={14} /><span className="text-sm font-medium">{hist}</span></div>
                          <button onClick={(e) => toggleFavorite(e, hist)} className="opacity-0 group-hover:opacity-100 p-1"><Star size={14} className="text-slate-300 dark:text-slate-600" /></button>
                        </div>
                       ))}
                    </div>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {Object.values(Platform).map(p => (
                    <button key={p} onClick={() => setState(prev => ({ ...prev, platform: p }))} className={`py-4 rounded-2xl border-2 font-black text-xs uppercase tracking-widest transition-all ${state.platform === p ? 'border-indigo-600 dark:border-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-md' : 'border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500 hover:border-slate-200 dark:hover:border-slate-700'}`}>{p}</button>
                  ))}
                </div>
              </div>
            </div>
            <div className="space-y-4">
              <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Claim Scope Synopsis</label>
              <textarea rows={14} placeholder="Ex: 'Water intrusion from appliance leak...'" className="w-full px-6 py-4 border border-slate-200 dark:border-slate-700 rounded-3xl outline-none bg-slate-50/50 dark:bg-slate-800/50 hover:bg-white dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 transition-all text-sm font-medium" value={state.synopsis} onChange={e => setState(p => ({ ...p, synopsis: e.target.value }))} />
              {(state.synopsis?.length || 0) > 100 && (
                <div className="flex items-center gap-2 px-4 py-2 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-green-100 dark:border-green-900/30">
                  <CheckCircle2 size={14} /> Detailed Synopsis Mode Active
                </div>
              )}
            </div>
          </div>
          <div className="mt-10 flex justify-end">
            <button onClick={() => setStep(2)} className="bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 transition-all shadow-xl">Next: Areas & Elevations <ChevronRight size={18} /></button>
          </div>
        </div>
      );
    }

    if (step === 2) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in">
          <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-10 gap-6">
            <h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100"><LayoutGrid className="text-indigo-600 dark:text-indigo-400" /> Structural Zones</h2>
            <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
               <div className="flex-1 space-y-2">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Interior Label</p>
                 <div className="flex flex-wrap gap-2">
                   {INTERIOR_LABELS.slice(0, 6).map(label => (
                     <button key={label} onClick={() => addRoom(label, 'Room')} className="px-3 py-1.5 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 hover:bg-indigo-100 dark:hover:bg-indigo-900/30 rounded-lg text-[10px] font-black uppercase tracking-tight transition-all border border-indigo-100 dark:border-indigo-900/40">
                       {label}
                     </button>
                   ))}
                   <select 
                     onChange={(e) => { if(e.target.value) addRoom(e.target.value, 'Room'); e.target.value = ''; }}
                     className="px-3 py-1.5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-lg text-[10px] font-black uppercase outline-none"
                   >
                     <option value="">More...</option>
                     {INTERIOR_LABELS.slice(6).map(label => <option key={label} value={label}>{label}</option>)}
                   </select>
                 </div>
               </div>
               <div className="flex-1 space-y-2">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Exterior Elevation</p>
                 <div className="flex flex-wrap gap-2">
                   {EXTERIOR_LABELS.map(label => (
                     <button key={label} onClick={() => addRoom(label, 'Exterior Face')} className="px-3 py-1.5 bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/30 rounded-lg text-[10px] font-black uppercase tracking-tight transition-all border border-amber-100 dark:border-amber-900/40">
                       {label}
                     </button>
                   ))}
                 </div>
               </div>
            </div>
          </div>

          {state.rooms.length === 0 ? (
            <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700">
               <Building2 size={48} className="mb-4" />
               <p className="font-black text-xs uppercase tracking-widest">Select structural labels above to begin scoping</p>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
              {state.rooms.map(room => (
                <div key={room.id} className="p-6 border border-slate-100 dark:border-slate-800 rounded-3xl bg-white dark:bg-slate-900 shadow-sm flex items-center justify-between group hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-all animate-in">
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-2xl ${room.type === 'Room' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400'}`}>{room.type === 'Room' ? <Building2 size={20} /> : <Camera size={20} />}</div>
                    <div>
                      <input className="font-black text-slate-800 dark:text-slate-100 focus:outline-none text-sm bg-transparent" value={room.name} onChange={(e) => setState(p => ({ ...p, rooms: p.rooms.map(r => r.id === room.id ? { ...r, name: e.target.value } : r) }))} />
                      <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-tighter">{room.type}</p>
                    </div>
                  </div>
                  <button onClick={() => setState(p => ({ ...p, rooms: p.rooms.filter(r => r.id !== room.id) }))} className="p-2 text-slate-200 dark:text-slate-700 hover:text-red-500 dark:hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={18} /></button>
                </div>
              ))}
            </div>
          )}

          <div className="mt-12 flex justify-between">
            <button onClick={() => setStep(1)} className="px-8 py-3 text-slate-400 dark:text-slate-500 font-black text-xs uppercase hover:text-slate-600 dark:hover:text-slate-300 transition-all">Back</button>
            <button onClick={() => setStep(3)} className="bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase flex items-center gap-3 transition-all shadow-xl">Next: Evidence & Docs <ChevronRight size={18} /></button>
          </div>
        </div>
      );
    }

    if (step === 3) {
      return (
        <div className="space-y-10 animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-8">
            <div className="flex items-center justify-between mb-10">
              <div><h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100"><Files className="text-indigo-600 dark:text-indigo-400" /> Evidence & Documents</h2></div>
              <div className="flex gap-3">
                 <label className="cursor-pointer bg-slate-900 dark:bg-slate-800 text-white px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-lg hover:bg-black dark:hover:bg-slate-700">
                    <Map size={14} /> Measurement Report
                    <input type="file" multiple accept=".pdf,.jpg,.png" className="hidden" onChange={(e) => handleEvidenceUpload('Measurement Report', undefined, e.target.files)} />
                 </label>
                 <label className="cursor-pointer bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-md">
                    <Files size={14} /> Scope PDF
                    <input type="file" multiple accept=".pdf" className="hidden" onChange={(e) => handleEvidenceUpload('PDF Package', undefined, e.target.files)} />
                 </label>
              </div>
            </div>

            <div className="space-y-12">
               {state.evidence.some(e => !e.roomId) && (
                 <div className="bg-slate-50/50 dark:bg-slate-800/30 rounded-3xl p-6 border border-slate-100 dark:border-slate-800 border-dashed grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
                    {state.evidence.filter(e => !e.roomId).map(doc => (
                      <div key={doc.id} className="relative aspect-[3/4] rounded-2xl overflow-hidden border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 group p-4 flex flex-col items-center justify-center text-center shadow-sm hover:shadow-md transition-all">
                        <EvidenceTypeIcon type={doc.type} />
                        <span className="mt-2 text-[10px] font-bold text-slate-600 dark:text-slate-400 line-clamp-2 uppercase tracking-tighter">{doc.fileName}</span>
                        <button onClick={() => setState(p => ({ ...p, evidence: p.evidence.filter(ev => ev.id !== doc.id) }))} className="absolute -top-1 -right-1 p-2 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-all shadow-lg scale-75"><X size={16} /></button>
                      </div>
                    ))}
                 </div>
               )}

               <div className="space-y-10">
                  {state.rooms.map(room => (
                    <div key={room.id} className="pt-6 border-t border-slate-50 dark:border-slate-800">
                       <div className="flex items-center justify-between mb-6">
                          <h3 className="font-black text-slate-800 dark:text-slate-200 tracking-tight text-lg flex items-center gap-3"><div className="h-5 w-1 bg-indigo-500 rounded-full"></div>{room.name}</h3>
                          <div className="flex flex-wrap gap-2">
                            <button onClick={() => startCamera(room.id)} className="bg-indigo-600 dark:bg-indigo-500 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-md hover:bg-indigo-700 dark:hover:bg-indigo-400">
                              <Camera size={14} /> Take Photo
                            </button>
                            <label className="cursor-pointer bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-sm">
                              <ImageIcon size={14} /> Add Photos
                              <input type="file" multiple accept="image/*" className="hidden" onChange={(e) => handleEvidenceUpload('Photo', room.id, e.target.files)} />
                            </label>
                          </div>
                       </div>
                       <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
                          {state.evidence.filter(e => e.roomId === room.id).map(item => (
                            <div key={item.id} className="relative aspect-square rounded-2xl overflow-hidden border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 group shadow-sm">
                               {item.mimeType.includes('image') ? <img src={item.base64} alt="evidence" className="w-full h-full object-cover" /> : <div className="w-full h-full flex flex-col items-center justify-center p-4"><Files className="text-slate-300 dark:text-slate-600 mb-2" size={24} /><span className="text-[9px] font-black text-slate-400 dark:text-slate-500 text-center uppercase tracking-tighter">{item.fileName}</span></div>}
                               <button onClick={() => setState(p => ({ ...p, evidence: p.evidence.filter(ev => ev.id !== item.id) }))} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-all shadow-lg scale-75"><X size={12} /></button>
                            </div>
                          ))}
                       </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="mt-16 flex justify-between border-t border-slate-100 dark:border-slate-800 pt-10">
              <button onClick={() => setStep(2)} className="px-8 py-3 text-slate-400 dark:text-slate-500 font-black text-xs uppercase tracking-widest">Back</button>
              <button onClick={runInvestigationAnalysis} disabled={state.isAnalyzing} className="bg-indigo-600 dark:bg-indigo-500 hover:bg-indigo-700 dark:hover:bg-indigo-400 disabled:opacity-50 text-white px-12 py-5 rounded-3xl font-black text-sm uppercase flex items-center gap-4 transition-all shadow-2xl shadow-indigo-100 dark:shadow-indigo-900/20 active:scale-95">
                {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Analyzing...</> : <><CheckCircle2 size={24} /> Generate Forensic Scope</>}
              </button>
            </div>
          </div>
        </div>
      );
    }

    if (step === 4 && state.analysisComplete) {
      return (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
          <div className="grid md:grid-cols-3 gap-8">
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg flex items-center gap-6">
              <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl text-indigo-600 dark:text-indigo-400"><FileText size={28} /></div>
              <div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Line Items</p><h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">{state.lineItems.length}</h3></div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg flex items-center gap-6">
              <div className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl text-amber-600 dark:text-amber-400"><Files size={28} /></div>
              <div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Evidence Analyzed</p><h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">{state.evidence.length}</h3></div>
            </div>
          </div>

          <div className="grid lg:grid-cols-5 gap-10">
            <div className="lg:col-span-2 space-y-8">
               <h2 className="text-xl font-black px-4 text-slate-800 dark:text-slate-200 uppercase tracking-tight">Evidence Log</h2>
               <div className="space-y-8 max-h-[1200px] overflow-auto pr-6 custom-scrollbar">
                  {state.evidence.map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-xl overflow-hidden group">
                       <div className="relative aspect-video bg-slate-50 dark:bg-slate-800">
                          {item.mimeType.includes('image') ? <img src={item.base64} alt="Evidence" className="w-full h-full object-cover" /> : <div className="w-full h-full flex flex-col items-center justify-center"><FileSearch className="text-indigo-200 dark:text-slate-700" size={48} /></div>}
                          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                            <div className="px-4 py-1.5 bg-black/70 backdrop-blur rounded-xl text-[9px] font-black text-white uppercase tracking-widest">{state.rooms.find(r => r.id === item.roomId)?.name || "Global Document"}</div>
                          </div>
                       </div>
                       <div className="p-6 space-y-4">
                          <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-bold tracking-tight">{item.detectedDamage?.observations}</p>
                          <div className="pt-4 border-t border-slate-50 dark:border-slate-800"><p className="text-sm text-indigo-900 dark:text-indigo-400 italic font-black">{item.label}</p></div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
            <div className="lg:col-span-3">
               <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-800 flex flex-col h-full overflow-hidden">
                  <div className="p-8 border-b dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20 flex items-center justify-between">
                     <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase">Generated Scope</h2>
                     <button className="text-white bg-indigo-600 dark:bg-indigo-500 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase shadow-lg hover:bg-indigo-700 dark:hover:bg-indigo-400 transition-all">Download {state.platform}</button>
                  </div>
                  <div className="flex-1 p-8 space-y-10">
                     {state.rooms.map(room => {
                        const roomItems = state.lineItems.filter(li => li.roomName === room.name);
                        if (roomItems.length === 0) return null;
                        return (
                          <div key={room.id} className="animate-in fade-in slide-in-from-left-4 duration-700">
                             <div className="flex items-center gap-3 mb-6"><div className="h-5 w-1.5 bg-indigo-500 dark:bg-indigo-400 rounded-full"></div><h3 className="font-black text-slate-800 dark:text-slate-200 text-sm uppercase tracking-widest">{room.name}</h3></div>
                             <div className="grid gap-4">
                                {roomItems.map(item => (
                                  <div key={item.id} className="p-6 border border-slate-50 dark:border-slate-800 rounded-3xl bg-slate-50/30 dark:bg-slate-800/10 hover:bg-white dark:hover:bg-slate-800 transition-all group">
                                     <div className="flex items-start justify-between gap-6 mb-4">
                                        <div className="flex items-center gap-3"><span className="font-mono text-[10px] font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-lg border border-indigo-100 dark:border-indigo-900/30 tracking-tighter">{item.code}</span><span className="font-black text-slate-900 dark:text-slate-100">{item.description}</span></div>
                                        <div className="text-right shrink-0"><p className="text-lg font-black text-indigo-600 dark:text-indigo-400 tracking-tighter">{item.quantity} {item.unit}</p></div>
                                     </div>
                                     <div className="flex items-start gap-4 text-slate-500 dark:text-slate-400 bg-white dark:bg-slate-900/50 p-4 rounded-2xl border border-slate-50 dark:border-slate-800 text-[11px] leading-relaxed shadow-sm"><Info size={16} className="mt-0.5 shrink-0 text-indigo-300 dark:text-slate-600" /><span><strong className="text-indigo-600 dark:text-indigo-400 uppercase text-[9px] font-black mr-1">Justification:</strong> {item.justification}</span></div>
                                  </div>
                                ))}
                             </div>
                          </div>
                        );
                     })}
                  </div>
               </div>
            </div>
          </div>
          <div className="flex justify-center pt-10 pb-20"><button onClick={() => window.location.reload()} className="px-16 py-6 bg-slate-900 dark:bg-slate-800 text-white rounded-3xl font-black text-xs uppercase tracking-widest hover:bg-black dark:hover:bg-slate-700 transition-all shadow-2xl active:scale-95">Start New Investigation</button></div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Universal Header */}
      <header className="flex flex-col md:flex-row items-center justify-between mb-12 pb-6 border-b border-slate-200 dark:border-slate-800 gap-6">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 dark:bg-indigo-500 p-2 rounded-2xl text-white shadow-xl shadow-indigo-200 dark:shadow-none"><ClipboardCheck size={32} /></div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight leading-none">AdjusterAI</h1>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-[0.2em] mt-1.5">Enterprise Estimating Suite</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-2xl shadow-inner backdrop-blur-sm">
            <button onClick={() => handleModeToggle(AppMode.INVESTIGATION)} className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.INVESTIGATION ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>Investigation</button>
            <button onClick={() => handleModeToggle(AppMode.COMPARISON)} className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.COMPARISON ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>Comparison</button>
          </div>

          <button onClick={toggleTheme} className="p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-800 transition-all text-slate-600 dark:text-slate-400">
            {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
          </button>
        </div>

        <div className="hidden lg:flex items-center gap-6">
           <div className="flex items-center gap-2"><Zap size={14} className="text-amber-500 fill-amber-500" /><span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Gemini 3.0 Pro</span></div>
           <div className="h-4 w-px bg-slate-200 dark:bg-slate-800"></div>
           <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Build 2.6.1</span>
        </div>
      </header>

      <main className="min-h-[600px]">
        {state.mode === AppMode.COMPARISON ? renderComparisonFlow() : renderInvestigationFlow()}
      </main>

      {/* Camera Capture Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border border-white/10">
            <video ref={videoRef} autoPlay playsInline className="w-full aspect-[4/3] object-cover" />
            <canvas ref={canvasRef} className="hidden" />

            <div className="p-6 flex items-center justify-between bg-slate-800">
               <button onClick={stopCamera} className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all"><X size={24} /></button>
               <button onClick={capturePhoto} className="group relative">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center transition-all group-active:scale-90 group-hover:scale-110">
                    <div className="w-14 h-14 border-4 border-slate-800 rounded-full" />
                  </div>
               </button>
               <div className="w-12 h-12" /> {/* Spacer */}
            </div>

            <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 border border-white/10">
               <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
               <span className="text-[10px] font-black text-white uppercase tracking-widest">Live: {state.rooms.find(r => r.id === cameraRoomId)?.name || 'General'}</span>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-20 pt-10 border-t border-slate-200 dark:border-slate-800 text-center space-y-3 pb-12">
        <p className="text-xs text-slate-400 dark:text-slate-500 font-medium tracking-tight">© 2024 AdjusterAI. Symbility and Cotality mapping active.</p>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

export enum Platform {
  XACTIMATE = 'Xactimate',
  SYMBILITY_COTALITY = 'Symbility / Cotality'
}

export enum AppMode {
  DASHBOARD = 'Dashboard',
  INVESTIGATION = 'Investigation',
  COMPARISON = 'Comparison',
  SETTINGS = 'Settings'
}

export type DamageCategory = 'Water' | 'Fire' | 'Structural' | 'Cosmetic' | 'Mold/Microbial' | 'Unknown';

export type EvidenceType = 'Photo' | 'PDF Package' | 'Scope Sheet' | 'Measurement Report' | 'Technical Document' | 'Estimate File';

export interface Room {
  id: string;
  name: string;
  type: 'Room' | 'Exterior Face';
}

export interface EvidenceItem {
  id: string;
  roomId?: string;
  type: EvidenceType;
  base64: string;
  mimeType: string;
  fileName: string;
  label?: string;
  detectedDamage?: {
    category: DamageCategory;
    confidence: number;
    observations: string;
  };
}

export interface LineItem {
  id: string;
  code: string;
  description: string;
  quantity: number;
  unit: string;
  roomName: string;
  justification?: string;
}

export interface VarianceDetail {
  category: string;
  itemA: string;
  itemB: string;
  delta: number;
  reason: string;
}

export interface ComparisonSummary {
  labor: { a: number; b: number };
  material: { a: number; b: number };
  total: { a: number; b: number };
}

export interface ComparisonResult {
  summary: ComparisonSummary;
  variances: VarianceDetail[];
  narrative: string;
}

export interface EstimationState {
  mode: AppMode;
  carrier: string;
  synopsis: string;
  platform: Platform;
  rooms: Room[];
  evidence: EvidenceItem[];
  lineItems: LineItem[];
  isAnalyzing: boolean;
  analysisComplete: boolean;
  customGuidelines?: string;
  uploadedGuidelineName?: string;

  // Comparison specific
  fileA?: EvidenceItem;
  fileB?: EvidenceItem;
  platformA: Platform;
  platformB: Platform;
  comparisonResult?: ComparisonResult;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
  Download,
  AlertCircle,
  Droplets,
  Flame,
  Construction,
  Sparkles,
  Info,
  ShieldCheck,
  Star,
  History,
  Search,
  Upload,
  ChevronDown,
  X,
  FileSearch,
  Map,
  Files,
  ArrowRightLeft,
  TrendingDown,
  TrendingUp,
  Minus,
  LayoutGrid,
  Zap,
  Shield,
  Maximize,
  Sun,
  Moon,
  Settings as SettingsIcon,
  Home,
  Save,
  BookOpen,
  Image as ImageIcon,
  Check,
  ChevronLeft
} from 'lucide-react';
import { Platform, Room, EvidenceItem, EstimationState, LineItem, DamageCategory, EvidenceType, AppMode, ComparisonResult } from './types';
import { fetchCarrierGuidelines, analyzeDamage, compareEstimates } from './services/geminiService';

const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites',
  THEME: 'adjuster_ai_theme',
  SAVED_GUIDELINES: 'adjuster_saved_guidelines'
};

const INTERIOR_LABELS = [
  'Bedroom', 'Bathroom', 'Kitchen', 'Living Room', 'Dining Room', 
  'Hallway', 'Garage', 'Basement', 'Attic', 'Laundry Room', 
  'Master Bedroom', 'Closet', 'Office'
];

const EXTERIOR_LABELS = [
  'Front Elevation', 'Rear Elevation', 'Left Elevation', 
  'Right Elevation', 'Roof', 'Fence', 'Detached Structure'
];

interface SavedGuideline {
  id: string;
  carrier: string;
  content: string;
  timestamp: number;
}

const DamageIcon = ({ category }: { category?: DamageCategory }) => {
  switch (category) {
    case 'Water': return <Droplets className="text-blue-500" size={16} />;
    case 'Fire': return <Flame className="text-orange-500" size={16} />;
    case 'Structural': return <Construction className="text-red-500" size={16} />;
    case 'Cosmetic': return <Sparkles className="text-purple-500" size={16} />;
    default: return <Info className="text-slate-400 dark:text-slate-500" size={16} />;
  }
};

const EvidenceTypeIcon = ({ type }: { type: EvidenceType }) => {
  switch (type) {
    case 'Photo': return <ImageIcon size={16} />;
    case 'PDF Package': return <Files size={16} />;
    case 'Measurement Report': return <Map size={16} />;
    case 'Scope Sheet': return <ClipboardCheck size={16} />;
    default: return <FileText size={16} />;
  }
};

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.THEME);
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [state, setState] = useState<EstimationState>({
    mode: AppMode.DASHBOARD,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [step, setStep] = useState(1);
  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [savedGuidelines, setSavedGuidelines] = useState<SavedGuideline[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);

  // Camera state
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    const guidelines = JSON.parse(localStorage.getItem(STORAGE_KEYS.SAVED_GUIDELINES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);
    setSavedGuidelines(guidelines);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ 
      ...prev, 
      mode, 
      analysisComplete: false, 
      isAnalyzing: false, 
      evidence: [], 
      lineItems: [], 
      comparisonResult: undefined,
      carrier: mode === AppMode.DASHBOARD ? '' : prev.carrier
    }));
    setStep(1);
    setFetchedGuidelines('');
  };

  const saveCurrentGuideline = () => {
    if (!state.carrier || !fetchedGuidelines) return;
    const newGuideline: SavedGuideline = {
      id: crypto.randomUUID(),
      carrier: state.carrier,
      content: fetchedGuidelines,
      timestamp: Date.now()
    };
    const updated = [newGuideline, ...savedGuidelines];
    setSavedGuidelines(updated);
    localStorage.setItem(STORAGE_KEYS.SAVED_GUIDELINES, JSON.stringify(updated));
    alert(`${state.carrier} guidelines saved to library.`);
  };

  const deleteSavedGuideline = (id: string) => {
    const updated = savedGuidelines.filter(g => g.id !== id);
    setSavedGuidelines(updated);
    localStorage.setItem(STORAGE_KEYS.SAVED_GUIDELINES, JSON.stringify(updated));
  };

  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraRoomId(roomId);
        setIsCameraOpen(true);
      }
    } catch (err) {
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
    setCameraRoomId(undefined);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId: cameraRoomId,
          type: 'Photo',
          base64,
          mimeType: 'image/jpeg',
          fileName: `capture_${Date.now()}.jpg`
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  const handleComparisonFileUpload = (side: 'A' | 'B', file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = e.target?.result as string;
      const evidence: EvidenceItem = {
        id: crypto.randomUUID(),
        type: 'Estimate File',
        base64,
        mimeType: file.type || 'application/octet-stream',
        fileName: file.name
      };
      setState(prev => ({ ...prev, [side === 'A' ? 'fileA' : 'fileB']: evidence }));
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!state.fileA || !state.fileB) {
      alert("Please upload both Estimate A and Estimate B before running comparison.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const result = await compareEstimates(state.fileA, state.fileB, state.platformA, state.platformB);
      setState(prev => ({ ...prev, comparisonResult: result, isAnalyzing: false, analysisComplete: true }));
      setStep(3);
    } catch (err) {
      alert("Comparison analysis failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));

    fetchGuidelines(carrierName);
  };

  const fetchGuidelines = async (carrierName: string) => {
    setGuidelinesLoading(true);
    try {
      const res = await fetchCarrierGuidelines(carrierName);
      setFetchedGuidelines(res);
    } catch (e) {
      console.error(e);
    } finally {
      setGuidelinesLoading(false);
    }
  };

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const addRoom = (baseLabel: string, type: 'Room' | 'Exterior Face') => {
    const existingSameLabels = state.rooms.filter(r => r.name.startsWith(baseLabel));
    let nextName = baseLabel;

    if (existingSameLabels.length > 0) {
      let maxNum = 0;
      existingSameLabels.forEach(r => {
        const match = r.name.match(new RegExp(`^${baseLabel}\\s*(\\d+)$`));
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        } else if (r.name === baseLabel) {
          if (maxNum === 0) maxNum = 1;
        }
      });
      nextName = `${baseLabel} ${maxNum + 1}`;
    }

    const newRoom: Room = { id: crypto.randomUUID(), name: nextName, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId,
          type,
          base64: e.target?.result as string,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const runInvestigationAnalysis = async () => {
    const hasDetailedSynopsis = (state.synopsis?.length || 0) > 100;

    if (state.evidence.length === 0 && !hasDetailedSynopsis) {
      alert("Please provide either a detailed synopsis or upload evidence (photos/reports) before running analysis.");
      return;
    }

    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform, 
        state.carrier || "Unknown Carrier", 
        state.synopsis || "No synopsis provided", 
        fetchedGuidelines || state.customGuidelines || "Standard industry rules", 
        state.evidence, 
        roomMap
      );
      setState(prev => ({ 
        ...prev, 
        lineItems: result.lineItems, 
        evidence: result.labeledEvidence, 
        isAnalyzing: false, 
        analysisComplete: true 
      }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const renderDashboard = () => {
    return (
      <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="text-center space-y-4">
          <h2 className="text-4xl font-black text-slate-800 dark:text-slate-100 tracking-tight">Enterprise Claims Dashboard</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium max-w-xl mx-auto">Select a workflow to begin. AdjusterAI automates forensic scoping and estimate auditing for insurance professionals.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-8 max-w-4xl mx-auto">
          <button 
            onClick={() => handleModeToggle(AppMode.INVESTIGATION)}
            className="group relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl hover:shadow-2xl hover:border-indigo-500 dark:hover:border-indigo-400 transition-all text-left overflow-hidden"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
              <ClipboardCheck size={120} className="text-indigo-600 dark:text-indigo-400" />
            </div>
            <div className="relative z-10 space-y-6">
              <div className="bg-indigo-50 dark:bg-indigo-900/30 w-16 h-16 rounded-2xl flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                <Search size={32} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">Claim Investigation</h3>
                <p className="text-slate-500 dark:text-slate-400 font-medium mt-2">Generate line items from site evidence and carrier-specific guidelines.</p>
              </div>
              <div className="flex items-center text-indigo-600 dark:text-indigo-400 font-black text-xs uppercase tracking-widest gap-2">
                Launch Workflow <ChevronRight size={16} />
              </div>
            </div>
          </button>

          <button 
            onClick={() => handleModeToggle(AppMode.COMPARISON)}
            className="group relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl hover:shadow-2xl hover:border-amber-500 dark:hover:border-amber-400 transition-all text-left overflow-hidden"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
              <ArrowRightLeft size={120} className="text-amber-600 dark:text-amber-400" />
            </div>
            <div className="relative z-10 space-y-6">
              <div className="bg-amber-50 dark:bg-amber-900/30 w-16 h-16 rounded-2xl flex items-center justify-center text-amber-600 dark:text-amber-400">
                <ArrowRightLeft size={32} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">Estimate Comparison</h3>
                <p className="text-slate-500 dark:text-slate-400 font-medium mt-2">Identify variances between multi-platform estimates and audit quantity deltas.</p>
              </div>
              <div className="flex items-center text-amber-600 dark:text-amber-400 font-black text-xs uppercase tracking-widest gap-2">
                Launch Workflow <ChevronRight size={16} />
              </div>
            </div>
          </button>
        </div>

        <div className="max-w-4xl mx-auto space-y-6">
          <div className="flex items-center justify-between px-4">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <BookOpen size={16} /> Carrier Documentation Library
            </h3>
          </div>

          {savedGuidelines.length === 0 ? (
            <div className="bg-slate-50 dark:bg-slate-900/50 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-3xl p-12 text-center space-y-3">
              <Files className="text-slate-300 dark:text-slate-700 mx-auto" size={48} />
              <p className="text-slate-400 dark:text-slate-600 font-black text-xs uppercase tracking-widest">No saved carrier documentation found.</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {savedGuidelines.map(g => (
                <div key={g.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl p-6 shadow-sm hover:shadow-md transition-all group">
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-indigo-50 dark:bg-indigo-900/30 p-2 rounded-xl text-indigo-600 dark:text-indigo-400">
                      <Shield size={20} />
                    </div>
                    <button 
                      onClick={() => deleteSavedGuideline(g.id)}
                      className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <h4 className="font-black text-slate-800 dark:text-slate-100 truncate">{g.carrier} Guidelines</h4>
                  <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Archived {new Date(g.timestamp).toLocaleDateString()}</p>
                  <button 
                    onClick={() => {
                      setState(prev => ({ ...prev, mode: AppMode.INVESTIGATION, carrier: g.carrier }));
                      setFetchedGuidelines(g.content);
                      setStep(1);
                    }}
                    className="w-full mt-6 py-2.5 bg-slate-50 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-400 hover:bg-indigo-600 hover:text-white transition-all"
                  >
                    Use Specifications
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderSettings = () => {
    return (
      <div className="max-w-3xl mx-auto space-y-10 animate-in fade-in">
        <div className="flex items-center gap-4 mb-10">
