  PieChart,
  RefreshCw,
  SlidersHorizontal,
  DollarSign,
  Package,
  Users
} from 'lucide-react';
import { Platform, Room, EvidenceItem, EstimationState, LineItem, DamageCategory, EvidenceType, AppMode, ComparisonResult } from './types';
import { fetchCarrierGuidelines, analyzeDamage, compareEstimates } from './services/geminiService';

const STORAGE_KEYS = {
  HISTORY: 'adjuster_carrier_history',
  FAVORITES: 'adjuster_carrier_favorites',
  THEME: 'adjuster_ai_theme',
  SAVED_GUIDELINES: 'adjuster_saved_guidelines'
};

const INTERIOR_LABELS = ['Bedroom', 'Bathroom', 'Kitchen', 'Living Room', 'Dining Room', 'Hallway', 'Garage', 'Basement', 'Attic', 'Laundry Room', 'Master Bedroom', 'Closet', 'Office'];
const EXTERIOR_LABELS = ['Front Elevation', 'Rear Elevation', 'Left Elevation', 'Right Elevation', 'Roof', 'Fence', 'Detached Structure'];

interface SavedGuideline {
  id: string;
  carrier: string;
  content: string;
  timestamp: number;
}

const App: React.FC = () => {
  const [state, setState] = useState<EstimationState>({
    mode: AppMode.DASHBOARD,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [step, setStep] = useState(1);
  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [savedGuidelines, setSavedGuidelines] = useState<SavedGuideline[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    const guidelines = JSON.parse(localStorage.getItem(STORAGE_KEYS.SAVED_GUIDELINES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);
    setSavedGuidelines(guidelines);
  }, []);

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ ...prev, mode, analysisComplete: false, isAnalyzing: false, evidence: [], lineItems: [], comparisonResult: undefined }));
    setStep(1);
    setFetchedGuidelines('');
  };

  const addRoom = (baseLabel: string, type: 'Room' | 'Exterior Face') => {
    const existingSameLabels = state.rooms.filter(r => r.name.startsWith(baseLabel));
    let nextName = baseLabel;
    if (existingSameLabels.length > 0) {
      let maxNum = 0;
      existingSameLabels.forEach(r => {
        const match = r.name.match(new RegExp(`^${baseLabel}\\s*(\\d+)$`));
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        } else if (r.name === baseLabel) {
          if (maxNum === 0) maxNum = 1;
        }
      });
      nextName = `${baseLabel} ${maxNum + 1}`;
    }
    const newRoom: Room = { id: crypto.randomUUID(), name: nextName, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = { id: crypto.randomUUID(), roomId, type, base64: e.target?.result as string, mimeType: file.type, fileName: file.name };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  // Fix: Implemented startCamera to resolve the missing function error and enable video streaming.
  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      setCameraRoomId(roomId);
      setIsCameraOpen(true);
    } catch (err) {
      console.error("Camera access error:", err);
      alert("Could not access camera. Please check permissions.");
    }
  };

  // Fix: Implemented stopCamera to release media resources and close the camera interface.
  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  // Fix: Implemented capturePhoto to save current video frame as an EvidenceItem.
  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        const newItem: EvidenceItem = { 
          id: crypto.randomUUID(), 
          roomId: cameraRoomId, 
          type: 'Photo', 
          base64: dataUrl, 
          mimeType: 'image/jpeg', 
          fileName: `capture-${Date.now()}.jpg` 
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  // Fix: Added effect to sync the media stream with the video element once the camera modal is rendered.
  useEffect(() => {
    if (isCameraOpen && videoRef.current && streamRef.current) {
      videoRef.current.srcObject = streamRef.current;
    }
  }, [isCameraOpen]);

  const runInvestigationAnalysis = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(state.platform, state.carrier || "Unknown", state.synopsis || "", fetchedGuidelines || "", state.evidence, roomMap);
      setState(prev => ({ ...prev, lineItems: result.lineItems, evidence: result.labeledEvidence, isAnalyzing: false, analysisComplete: true }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const SidebarItem = ({ icon: Icon, label, active, onClick }: { icon: any, label: string, active?: boolean, onClick: () => void }) => (
    <button 
      onClick={onClick}
      className={`w-full flex items-center gap-4 px-6 py-4 transition-all border-l-4 ${active ? 'bg-indigo-600/10 border-indigo-600 text-indigo-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
    >
      <Icon size={20} />
      <span className="font-bold text-sm">{label}</span>
    </button>
  );

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-black tracking-tight text-white">Dashboard</h2>
          <p className="text-slate-500 text-xs font-medium">Claim health at a glance</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex bg-brand-card p-1 rounded-xl">
             {['TODAY', '7D', '30D', 'YTD'].map(t => (
               <button key={t} className={`px-4 py-1.5 text-[10px] font-black rounded-lg ${t === '30D' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}>{t}</button>
             ))}
          </div>
          <button className="flex items-center gap-2 px-4 py-2 bg-brand-card border border-brand-border rounded-xl text-xs font-bold text-slate-300">
            <SlidersHorizontal size={14} /> Customize
          </button>
          <button className="flex items-center gap-2 px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/30 rounded-xl text-xs font-bold">
            <RefreshCw size={14} /> Sync
          </button>
        </div>
      </div>

      {/* Launchpad Progress Section */}
      <div className="bg-brand-card/50 border border-brand-border rounded-2xl p-8 space-y-6 relative overflow-hidden">
        <div className="flex items-center gap-3 text-indigo-400 text-[10px] font-black uppercase tracking-widest">
          <Zap size={14} /> Launchpad
        </div>
        <div className="flex items-center justify-between">
          <p className="text-slate-400 text-xs font-medium max-w-lg">Let's get you setup for success by completing a few quick tasks so you can experience AdjusterAI to the fullest.</p>
          <div className="flex gap-3">
            {['Profile', 'Bank', 'Branding', 'Carrier Specs'].map((item, idx) => (
              <button key={item} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${idx === 0 ? 'bg-indigo-600/10 border-indigo-600/50 text-indigo-400' : 'bg-brand-card border-brand-border text-slate-500 hover:text-slate-300'}`}>
                {idx > 0 && <Check size={14} className="inline mr-2" />} {item}
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-2">
          <div className="h-1.5 w-full bg-brand-border rounded-full overflow-hidden">
            <div className="h-full w-1/2 bg-indigo-600 shadow-[0_0_10px_rgba(79,70,229,0.5)]" />
          </div>
          <p className="text-[10px] font-black text-indigo-400 uppercase">50% Complete</p>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="flex gap-4">
        <button onClick={() => handleModeToggle(AppMode.INVESTIGATION)} className="flex items-center gap-2 px-6 py-3 bg-indigo-600/10 border border-indigo-600/30 rounded-xl text-xs font-bold text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all">
          <Plus size={16} /> New Investigation
        </button>
        <button onClick={() => handleModeToggle(AppMode.COMPARISON)} className="flex items-center gap-2 px-6 py-3 bg-blue-600/10 border border-blue-600/30 rounded-xl text-xs font-bold text-blue-400 hover:bg-blue-600 hover:text-white transition-all">
          <ArrowRightLeft size={16} /> New Comparison
        </button>
        <button className="flex items-center gap-2 px-6 py-3 bg-purple-600/10 border border-purple-600/30 rounded-xl text-xs font-bold text-purple-400 hover:bg-purple-600 hover:text-white transition-all">
          <Map size={16} /> New Report
        </button>
        <button className="flex items-center gap-2 px-6 py-3 bg-amber-600/10 border border-amber-600/30 rounded-xl text-xs font-bold text-amber-400 hover:bg-amber-600 hover:text-white transition-all">
          <History size={16} /> Log Batch
        </button>
      </div>

      {/* Metric Cards */}
      <div className="grid md:grid-cols-4 gap-6">
        {[
          { label: 'CLAIMS PROCESSED', value: '42', sync: true, icon: Building2, color: 'text-indigo-400' },
          { label: 'SCOPE REVENUE', value: '$284,350', trend: '+12% PERF', icon: TrendingUp, color: 'text-blue-400' },
          { label: 'LINE ITEMS FOUND', value: '1,420', trend: '+84% PERF', icon: DollarSign, color: 'text-purple-400' },
          { label: 'DISPUTED VARIANCE', value: '$1,665', trend: '-4% PERF', icon: TrendingDown, color: 'text-rose-400' }
        ].map((m, i) => (
          <div key={i} className="bg-brand-card p-8 rounded-2xl border border-brand-border flex flex-col justify-between group hover:border-slate-700 transition-all">
            <div className="flex justify-between items-start">
              <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">{m.label}</p>
                <h4 className="text-3xl font-black text-white">{m.value}</h4>
              </div>
              <div className={`p-2 rounded-lg bg-brand-dark ${m.color}`}><m.icon size={20} /></div>
            </div>
            <div className="mt-6 flex items-center justify-between">
              {m.sync && <p className="text-[9px] font-black text-slate-500 uppercase cursor-pointer hover:text-indigo-400">2 ACCOUNTS <span className="text-indigo-400 ml-2">SYNC</span></p>}
              {m.trend && <p className={`text-[9px] font-black uppercase ${m.trend.includes('+') ? 'text-green-500' : 'text-rose-500'}`}>{m.trend}</p>}
            </div>
          </div>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-8">
        <div className="bg-brand-card p-8 rounded-2xl border border-brand-border h-64 flex flex-col justify-center items-center text-slate-700">
           <PieChart size={48} className="mb-4 opacity-20" />
           <p className="text-xs font-black uppercase tracking-widest opacity-40">Revenue Growth Visualization</p>
        </div>
        <div className="bg-brand-card p-8 rounded-2xl border border-brand-border h-64 flex flex-col justify-center items-center text-slate-700">
           <History size={48} className="mb-4 opacity-20" />
           <p className="text-xs font-black uppercase tracking-widest opacity-40">Recent Claim Activity</p>
        </div>
      </div>
    </div>
  );

  const renderInvestigationFlow = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
      <div className="flex items-center gap-4">
        <button onClick={() => handleModeToggle(AppMode.DASHBOARD)} className="p-2 text-slate-500 hover:text-white"><ChevronLeft size={24}/></button>
        <h2 className="text-2xl font-black text-white">Forensic Investigation</h2>
      </div>

      {step === 1 && (
        <div className="bg-brand-card border border-brand-border rounded-3xl p-10 space-y-10 max-w-4xl">
          <div className="grid md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <div className="relative">
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">Carrier Context</label>
                <button 
                  onClick={() => setIsCarrierDropdownOpen(!isCarrierDropdownOpen)}
                  className="w-full flex items-center justify-between px-6 py-4 bg-brand-dark border border-brand-border rounded-2xl text-slate-300 font-bold hover:border-indigo-500 transition-all"
                >
                  <span>{state.carrier || "Search Carriers..."}</span>
                  <ChevronDown size={18} />
                </button>
              </div>
              <div className="space-y-3">
                 <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest">Target Estimating Engine</label>
                 <div className="grid grid-cols-2 gap-4">
                   {[Platform.XACTIMATE, Platform.SYMBILITY_COTALITY].map(p => (
                     <button key={p} onClick={() => setState(s => ({...s, platform: p}))} className={`py-4 rounded-2xl border font-black text-[10px] uppercase tracking-widest transition-all ${state.platform === p ? 'border-indigo-600 bg-indigo-600/10 text-indigo-400' : 'border-brand-border bg-brand-dark text-slate-500 hover:border-slate-700'}`}>
                       {p}
                     </button>
                   ))}
                 </div>
              </div>
            </div>
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest">Site Synopsis</label>
              <textarea 
                rows={10} 
                className="w-full px-6 py-4 bg-brand-dark border border-brand-border rounded-2xl text-slate-300 text-sm outline-none focus:border-indigo-600 transition-all resize-none"
                placeholder="Narrate the damage scope here..."
                value={state.synopsis}
                onChange={e => setState(s => ({...s, synopsis: e.target.value}))}
              />
            </div>
          </div>
          <div className="flex justify-end pt-6">
            <button onClick={() => setStep(2)} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
              Initialize Zones <ChevronRight className="inline ml-2" size={16} />
            </button>
          </div>
        </div>
      )}

      {step === 2 && (
        <div className="bg-brand-card border border-brand-border rounded-3xl p-10 animate-in">
          <div className="flex items-center justify-between mb-10">
             <h3 className="text-xl font-black text-white">Structural Zones</h3>
             <div className="flex gap-4">
               {INTERIOR_LABELS.slice(0, 4).map(l => (
                 <button key={l} onClick={() => addRoom(l, 'Room')} className="px-4 py-2 bg-indigo-600/10 border border-indigo-600/30 text-indigo-400 rounded-xl text-[10px] font-black uppercase hover:bg-indigo-600 hover:text-white transition-all">{l}</button>
               ))}
               <button onClick={() => addRoom('Bedroom', 'Room')} className="p-2 bg-brand-dark border border-brand-border rounded-xl text-slate-500 hover:text-white"><Plus size={20}/></button>
             </div>
          </div>
          <div className="grid md:grid-cols-3 gap-6">
            {state.rooms.map(room => (
              <div key={room.id} className="p-6 bg-brand-dark border border-brand-border rounded-2xl flex items-center justify-between group">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-indigo-600/10 text-indigo-400 rounded-xl"><Building2 size={20}/></div>
                  <div>
                    <p className="text-white font-bold text-sm">{room.name}</p>
                    <p className="text-[9px] font-black text-slate-500 uppercase tracking-tighter">{room.type}</p>
                  </div>
                </div>
                <button onClick={() => setState(s => ({...s, rooms: s.rooms.filter(r => r.id !== room.id)}))} className="text-slate-700 hover:text-rose-500"><Trash2 size={18}/></button>
              </div>
            ))}
          </div>
          <div className="mt-12 flex justify-between border-t border-brand-border pt-8">
            <button onClick={() => setStep(1)} className="text-slate-500 font-black text-xs uppercase">Back</button>
            <button onClick={() => setStep(3)} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase active:scale-95 transition-all">Proceed to Evidence</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="bg-brand-card border border-brand-border rounded-3xl p-10 space-y-12">
           <div className="flex justify-between items-center">
             <h3 className="text-xl font-black text-white">Evidence Upload</h3>
             <div className="flex gap-4">
               <label className="cursor-pointer px-6 py-3 bg-indigo-600/10 border border-indigo-600/30 text-indigo-400 rounded-xl text-xs font-bold flex items-center gap-2 hover:bg-indigo-600 hover:text-white transition-all">
                 <Upload size={16} /> Bulk Upload
                 <input type="file" multiple className="hidden" onChange={e => handleEvidenceUpload('Photo', undefined, e.target.files)} />
               </label>
             </div>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
             {state.evidence.map(item => (
               <div key={item.id} className="aspect-square bg-brand-dark border border-brand-border rounded-2xl overflow-hidden relative group">
                 {item.mimeType.includes('image') ? <img src={item.base64} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" /> : <div className="w-full h-full flex items-center justify-center text-slate-600"><Files size={40}/></div>}
                 <button onClick={() => setState(s => ({...s, evidence: s.evidence.filter(e => e.id !== item.id)}))} className="absolute top-2 right-2 p-1.5 bg-rose-600 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-all"><X size={12}/></button>
               </div>
             ))}
             {/* Fix: Calling startCamera which is now correctly defined */}
             <button onClick={() => startCamera()} className="aspect-square border-2 border-dashed border-brand-border rounded-2xl flex flex-col items-center justify-center text-slate-600 hover:text-indigo-400 hover:border-indigo-600/50 transition-all">
               <Camera size={32} className="mb-2" />
               <span className="text-[10px] font-black uppercase">Capture</span>
             </button>
           </div>
           <div className="flex justify-end pt-8">
             <button onClick={runInvestigationAnalysis} disabled={state.isAnalyzing} className="px-12 py-5 bg-indigo-600 text-white rounded-2xl font-black text-sm uppercase flex items-center gap-3 active:scale-95 transition-all disabled:opacity-50">
               {state.isAnalyzing ? <Loader2 className="animate-spin" /> : <Zap size={20} className="fill-white" />} Run Forensic Analysis
             </button>
           </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="flex min-h-screen">
      {/* Sidebar */}
      <aside className="w-64 bg-brand-sidebar border-r border-brand-border flex flex-col fixed h-full z-50">
        <div className="p-8 space-y-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-600/20">
              <ClipboardCheck size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black text-white tracking-tight leading-none">AdjusterAI</h1>
              <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1">Bookkeeping</p>
            </div>
          </div>

          <button className="w-full flex items-center justify-between px-4 py-3 bg-brand-dark border border-brand-border rounded-xl text-xs font-bold text-slate-300">
            <div className="flex items-center gap-3">
              <div className="w-2 h-2 bg-indigo-500 rounded-full" />
              <span>Acme Roofing LLC</span>
            </div>
            <ChevronDown size={14} className="text-slate-600" />
          </button>
        </div>

        <nav className="flex-1 mt-4">
          <SidebarItem icon={Home} label="Dashboard" active={state.mode === AppMode.DASHBOARD} onClick={() => handleModeToggle(AppMode.DASHBOARD)} />
          <SidebarItem icon={Search} label="Investigation" active={state.mode === AppMode.INVESTIGATION} onClick={() => handleModeToggle(AppMode.INVESTIGATION)} />
          <SidebarItem icon={ArrowRightLeft} label="Comparison" active={state.mode === AppMode.COMPARISON} onClick={() => handleModeToggle(AppMode.COMPARISON)} />
          <SidebarItem icon={Files} label="Invoices" onClick={() => {}} />
          <SidebarItem icon={Package} label="Expenses" onClick={() => {}} />
          <SidebarItem icon={PieChart} label="Reports" onClick={() => {}} />
          <SidebarItem icon={SettingsIcon} label="Settings" active={state.mode === AppMode.SETTINGS} onClick={() => handleModeToggle(AppMode.SETTINGS)} />
        </nav>

        <div className="p-8 border-t border-brand-border">
          <div className="flex items-center gap-4 group cursor-pointer">
            <div className="w-10 h-10 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-slate-400 group-hover:border-indigo-500 transition-all">
              <Users size={20} />
            </div>
            <div>
              <p className="text-sm font-bold text-white leading-none">John Adjuster</p>
              <p className="text-[10px] text-slate-600 mt-1 font-medium">Enterprise Plan</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 ml-64 p-12 bg-brand-dark">
        {state.mode === AppMode.DASHBOARD && renderDashboard()}
        {state.mode === AppMode.INVESTIGATION && renderInvestigationFlow()}
        {state.mode === AppMode.COMPARISON && <div className="text-white">Comparison Workflow Implementation Underway...</div>}
        {state.mode === AppMode.SETTINGS && <div className="text-white">Settings Implementation Underway...</div>}
      </main>

      {/* Camera Capture Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-brand-dark/95 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl bg-brand-card rounded-3xl overflow-hidden shadow-2xl border border-brand-border">
            <video ref={videoRef} autoPlay playsInline className="w-full aspect-[4/3] object-cover" />
            <canvas ref={canvasRef} className="hidden" />
            <div className="p-8 flex items-center justify-between bg-brand-sidebar">
               {/* Fix: Using stopCamera for closing the modal */}
               <button onClick={stopCamera} className="p-3 bg-brand-dark hover:bg-slate-800 text-white rounded-full transition-all"><X size={24} /></button>
