        <div className="space-y-3">
          <div className="h-1.5 w-full bg-brand-border rounded-full overflow-hidden">
            <div className="h-full w-1/2 bg-brand-accent shadow-[0_0_15px_rgba(59,130,246,0.5)] transition-all duration-1000" />
