          <p className="text-slate-500 text-xs font-medium">Financial health at a glance</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex bg-brand-sidebar p-1 rounded-xl border border-brand-border">
             {['TODAY', '7D', '30D', '90D', 'YTD'].map(t => (
               <button key={t} className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${t === '30D' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>{t}</button>
             ))}
          </div>
          <button className="flex items-center gap-2 px-4 py-2 bg-brand-card border border-brand-border rounded-xl text-xs font-bold text-slate-300">
            <SlidersHorizontal size={14} /> Customize
          </button>
          <button className="flex items-center gap-2 px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/30 rounded-xl text-xs font-bold">
            <RefreshCw size={14} /> Sync
          </button>
        </div>
      </div>

      {/* Launchpad Section */}
