                {item.active ? <CheckCircle2 size={14} className="text-indigo-400" /> : <div className="w-1.5 h-1.5 rounded-full bg-slate-600" />} {item.label}
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <div className="h-1.5 w-full bg-brand-border rounded-full overflow-hidden">
            <div className="h-full w-1/2 bg-indigo-600 shadow-[0_0_15px_rgba(79,70,229,0.5)] transition-all duration-1000" />
