            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 bg-indigo-500 rounded-md shadow-[0_0_8px_rgba(79,70,229,0.6)]" />
              <span className="truncate">Acme Roofing LLC</span>
            </div>
            <ChevronDown size={14} className="text-slate-600" />
