            <canvas ref={canvasRef} className="hidden" />
            <div className="p-8 flex items-center justify-between bg-brand-sidebar border-t border-brand-border">
               <button onClick={stopCamera} className="p-3 bg-brand-dark hover:bg-slate-800 text-white rounded-full transition-all border border-brand-border shadow-md"><X size={24} /></button>
               <button onClick={capturePhoto} className="w-16 h-16 bg-indigo-600 rounded-full border-4 border-white/20 shadow-[0_0_20px_rgba(79,70,229,0.5)] active:scale-90 transition-all group">
